INSERT INTO public.ai_generated_items (id, store_id, job_id, type, title, content, source_document_ids, status, feedback_notes, created_by, created_at, updated_at) VALUES
	('374cb073-31e5-4cd5-8fd3-0b3d67427f67', 'b0396051-34a1-475b-addc-771e580a5224', '5823aa0e-fbea-4b49-9350-926848af82d5', 'sop', 'Customer Greeting and Product Area Introduction', '{"role": "New Associate", "tags": ["customer_service", "sales", "product_knowledge", "greeting"], "steps": [{"type": "action", "order": 1, "title": "Initial Customer Greeting", "description": "Greet every guest within 20 seconds of entering the store at either entrance. Say ''Hey, how are you today?'' then respond with a helpful/inspiring question such as ''Are you shopping for an event in particular?'' or ''We have some great pieces that would look great on you, would it be alright for me to pull a few down and set up a dressing room for you?''", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Assess Customer''s Product Interest", "description": "Observe which product area the customer gravitates toward or ask about their shopping needs to determine appropriate product introduction script.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Select Product Area Script", "description": "Choose the appropriate introduction script based on the product area customer is interested in", "decisionOptions": [{"action": "Ask ''Did you know that we''re a Free People Shop-in-Shop?'' and explain our selection based on their response", "condition": "If customer approaches Free People area"}, {"action": "Ask ''Have you ever shopped our shoes before?'' and explain open stock system and shoe wall operation", "condition": "If customer approaches shoes"}, {"action": "Ask ''Did you know that we carry a large selection of handmade jewelry?'' and introduce Nakamol, Flea Market Girl, and Lo Lady lines", "condition": "If customer approaches jewelry"}, {"action": "Ask ''Are you looking for a dress for a specific occasion?'' and provide location guidance and styling assistance", "condition": "If customer approaches dresses"}]}, {"type": "action", "order": 4, "title": "Make Product Recommendation", "description": "After introducing the product area, suggest a best-seller, new arrival, or personal favorite item from that section to encourage engagement and trial.", "decisionOptions": null}], "title": "Customer Greeting and Product Area Introduction", "summary": "Complete procedure for greeting customers and introducing them to specific product areas with appropriate scripts and recommendations."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:26:44.068475', '2026-04-14 18:26:44.068475'),
	('7bc4c08d-c1af-413d-8b81-a2ef2273b77a', 'b0396051-34a1-475b-addc-771e580a5224', '5823aa0e-fbea-4b49-9350-926848af82d5', 'sop', 'Dressing Room Setup and Social Shopping Enrollment', '{"role": "New Associate", "tags": ["dressing_room", "social_media", "loyalty_program", "customer_service"], "steps": [{"type": "action", "order": 1, "title": "Initiate Social Media Inquiry", "description": "Once customer is ready to try on items, ask ''Do you follow us on Instagram or Facebook?'' to assess their social media engagement level.", "decisionOptions": null}, {"type": "decision", "order": 2, "title": "Decision: Social Shopping Enrollment", "description": "Provide appropriate social shopping information based on customer''s current engagement level", "decisionOptions": [{"action": "Explain Instagram/Facebook presence and social shopping signup with 10% discount offer", "condition": "If customer says no to social media"}, {"action": "Explain social shopping process and 10% signup discount", "condition": "If customer follows but doesn''t know social shopping"}, {"action": "Encourage signup today for 10% discount", "condition": "If customer knows social shopping but not signed up"}, {"action": "Acknowledge their status and mention new arrivals posted first on social media", "condition": "If customer already signed up"}]}, {"type": "action", "order": 3, "title": "Provide Fitting Room Form", "description": "If customer agrees to social shopping signup, direct them to the form on clipboard in dressing room and explain the credit card on file process for security.", "decisionOptions": null}, {"type": "action", "order": 4, "title": "Offer Basic Pieces and Styling Support", "description": "Inform customer about available basic pieces: ''Be sure to let me know if you need a basic piece like a lace bra, bandeau, cami or slip. We have a great selection out here, and I''ve already put a few in your room to try on with pieces you chose.''", "decisionOptions": null}], "title": "Dressing Room Setup and Social Shopping Enrollment", "summary": "Process for setting up customers in dressing rooms while promoting social shopping enrollment and providing fitting assistance."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:26:44.077462', '2026-04-14 18:26:44.077462'),
	('844a45ec-9cb7-42a1-8989-a0c8e767c6d2', 'b0396051-34a1-475b-addc-771e580a5224', '5823aa0e-fbea-4b49-9350-926848af82d5', 'sop', 'Customer Checkout and Loyalty Program Enrollment', '{"role": "Lead", "tags": ["checkout", "loyalty_program", "customer_database", "promotions"], "steps": [{"type": "action", "order": 1, "title": "Initial Checkout Greeting", "description": "Greet customer with ''Hi! Did you find everything you needed today?'' Wait for customer response and respond accordingly to any needs or concerns.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Determine Customer Status", "description": "Ask ''Have you ever shopped with us before?'' to identify if customer is existing or new.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Process Customer Account", "description": "Handle customer account based on their shopping history", "decisionOptions": [{"action": "Ask for name, verify city/phone number, update address if needed. Consolidate duplicate accounts and note for deletion.", "condition": "If existing customer"}, {"action": "Explain loyalty program benefits and offer signup for today''s purchase", "condition": "If claims to be existing but not in system"}, {"action": "Offer Customer Loyalty Program explaining it''s FREE with rewards, early notifications, and birthday discount", "condition": "If new customer"}]}, {"type": "action", "order": 4, "title": "Complete Loyalty Program Enrollment", "description": "If customer agrees to join, enter phone number, first and last name, current physical mailing address, email address, and birthday month. If busy with line, collect minimal info and provide customer info card for completion.", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Apply Current Promotions", "description": "Inform customer of any current promotions and attach flyer to receipt or place in bag with receipt to ensure they have promotion details.", "decisionOptions": null}], "title": "Customer Checkout and Loyalty Program Enrollment", "summary": "Complete checkout process including customer identification, loyalty program enrollment, and promotional information distribution."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:26:44.092576', '2026-04-14 18:26:44.092576'),
	('85a2ca16-0eab-4077-8f12-c51df8463fd7', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Greeting and Product Area Introduction', '{"role": "New Associate", "tags": ["customer service", "greeting", "product knowledge", "sales"], "steps": [{"type": "action", "order": 1, "title": "Initial Greeting", "description": "Greet every guest within 20 seconds of entering the store at either entrance. Use the greeting: ''Hey, how are you today?'' Then respond with a helpful/inspiring question such as ''Are you shopping for an event in particular?'' or ''We have some great pieces that would look great on you, would it be alright for me to pull a few down and set up a dressing room for you?''", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Identify Customer''s Area of Interest", "description": "Based on where the customer moves or expresses interest, approach the appropriate product area and use the corresponding introduction script.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Customer Knowledge Assessment", "description": "Ask the area-specific knowledge question to determine customer familiarity", "decisionOptions": [{"action": "Use the detailed explanation script for that area, demonstrate features, and explain benefits", "condition": "If customer says no (unfamiliar)"}, {"action": "Use the abbreviated acknowledgment script and proceed to product suggestions", "condition": "If customer says yes (familiar)"}]}, {"type": "action", "order": 4, "title": "Make Product Suggestions", "description": "Always suggest a best-seller, new arrival, or personal favorite from the area. Use specific product knowledge to make personalized recommendations based on customer needs.", "decisionOptions": null}], "title": "Customer Greeting and Product Area Introduction", "summary": "Standardized approach for greeting customers within 20 seconds and introducing them to specific product areas with tailored scripts based on customer knowledge."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:57:10.672934', '2026-04-14 18:57:10.672934'),
	('d9703a34-b732-4860-9e02-51056253d3c0', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Add-On Sales and Transaction Completion', '{"role": "Manager", "tags": ["upselling", "add-on sales", "transaction management"], "steps": [{"type": "action", "order": 1, "title": "Identify Add-On Opportunities", "description": "Once customer commits to main purchase, immediately assess complementary items that enhance their selection. Consider accessories, coordinating pieces, care products, or items for different occasions that align with their demonstrated style preferences.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Strategic Add-On Presentation", "description": "Present 1-3 carefully selected add-on items that genuinely enhance the customer''s main purchase. Explain how each item complements their selection and adds value to their wardrobe. Keep suggestions relevant and avoid overwhelming them with too many options.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Customer Add-On Response", "description": "Proceed based on customer interest level in additional items", "decisionOptions": [{"action": "Allow them to see/try the items and provide styling suggestions", "condition": "If customer shows interest"}, {"action": "Respect their decision and proceed to checkout with enthusiasm", "condition": "If customer declines politely"}, {"action": "Simplify to one key accessory or offer to hold items for future consideration", "condition": "If customer seems overwhelmed"}]}, {"type": "action", "order": 4, "title": "Complete Transaction with Care Information", "description": "Process the sale efficiently while providing care instructions, return policy information, and contact details for any future styling needs. End with genuine appreciation and an invitation to return for future fashion needs.", "decisionOptions": null}], "title": "Add-On Sales and Transaction Completion", "summary": "Systematic approach to maximizing sales through appropriate add-on suggestions and ensuring complete customer satisfaction at point of purchase."}', '["dbad453e-938d-4762-9257-419abbfd73f6"]', 'in_review', NULL, '46870047', '2026-04-14 18:58:25.672451', '2026-04-14 18:58:25.672451'),
	('13bd4e49-8135-4102-bb6d-15f032a2c923', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Loyalty Program Enrollment at Checkout', '{"role": "Lead", "tags": ["checkout", "loyalty program", "customer retention", "data collection"], "steps": [{"type": "action", "order": 1, "title": "Initial Checkout Greeting", "description": "Start with ''Hi! Did you find everything you needed today?'' Wait for customer response and respond accordingly to any needs or concerns.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Check Customer Status", "description": "Ask ''Have you ever shopped with us before?'' to determine if customer is in the system.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Customer Account Status", "description": "Determine next steps based on customer''s shopping history", "decisionOptions": [{"action": "Ask for their name, verify city/phone number, update address if needed. Use one account if duplicates exist", "condition": "If customer says yes"}, {"action": "Explain they''re missing loyalty perks and ask if they want to join today", "condition": "If customer says yes but not in system"}, {"action": "Proceed to loyalty program pitch", "condition": "If customer says no"}]}, {"type": "action", "order": 4, "title": "Loyalty Program Enrollment Pitch", "description": "Use script: ''Would you like to join our Customer Loyalty Program? It''s not like a credit card. It''s just a FREE rewards and perks program! You earn money back on your purchases, you''re the first to know about new arrivals, sales, and promotions, and you get a birthday discount during your birthday month! It only takes about 2 minutes to get signed up. Are you interested in joining today?''", "decisionOptions": null}, {"type": "decision", "order": 5, "title": "Decision: Enrollment Response", "description": "Handle customer''s decision about joining loyalty program", "decisionOptions": [{"action": "Enter full information: phone number, first/last name, mailing address, email, birthday month. If busy, use quick entry method with info card", "condition": "If customer says yes"}, {"action": "Continue with checkout process without enrollment", "condition": "If customer says no"}]}, {"type": "action", "order": 6, "title": "Complete Transaction", "description": "Inform customer of any current promotions and attach flyer to receipt or put in bag with receipt.", "decisionOptions": null}], "title": "Customer Loyalty Program Enrollment at Checkout", "summary": "Complete process for identifying existing customers and enrolling new customers in the loyalty program during checkout to maximize customer retention and data collection."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:57:10.688546', '2026-04-14 18:57:10.688546'),
	('3bea755f-2169-4648-b494-46ac78c91fcc', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Dressing Room Service and Social Media Engagement', '{"role": "Manager", "tags": ["dressing room", "social media", "upselling", "customer experience"], "steps": [{"type": "action", "order": 1, "title": "Social Media Assessment", "description": "When customer is ready to try on items, ask ''Do you follow us on Instagram or Facebook?'' to gauge their current social media engagement with the store.", "decisionOptions": null}, {"type": "decision", "order": 2, "title": "Decision: Social Media Following Status", "description": "Tailor approach based on customer''s social media engagement level", "decisionOptions": [{"action": "Introduce social shopping concept and 10% discount offer with signup form", "condition": "If customer says no"}, {"action": "Ask about social shopping knowledge and proceed accordingly", "condition": "If customer says yes"}]}, {"type": "action", "order": 3, "title": "Social Shopping Enrollment Process", "description": "Direct customer to form in dressing room on clipboard. Explain: ''You sign up for social shopping by filling out this form here, and when you''re checking out, we''ll put your credit card on file. Don''t worry, it''s only attached to your name in our computer system, so you''ll be the only one that can authorize charges, and if you sign up today, you get 10% off one item at the register!''", "decisionOptions": null}, {"type": "action", "order": 4, "title": "Provide Dressing Room Support", "description": "Once customer is in dressing room, offer: ''Be sure to let me know if you need a basic piece like a lace bra, bandeau, cami or slip. We have a great selection out here, and I''ve already put a few in your room to try on with pieces you chose. If I didn''t get the right size or style you needed, please don''t hesitate to ask for a different one.''", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Monitor and Assist", "description": "Regularly check on customer''s fitting progress, offer styling advice, suggest additional pieces, and ensure they have everything needed for a complete outfit.", "decisionOptions": null}], "title": "Dressing Room Service and Social Media Engagement", "summary": "Comprehensive process for providing exceptional dressing room service while promoting social shopping enrollment to increase digital engagement and sales."}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:57:10.895191', '2026-04-14 18:57:10.895191'),
	('fb8c70d9-c5b1-4520-9e75-1e52252601ac', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Customer Engagement & Product Area Scripts', '{"role": "New Associate", "title": "Customer Engagement & Product Area Scripts", "exercises": [{"guidance": "Greet within 20 seconds with ''Hey, how are you today?'' then ask ''Did you know that we''re a Free People Shop-in-Shop?'' Follow their response with the appropriate script and suggest a best-seller, new arrival, or personal favorite.", "question": "How would you approach this customer and what would you say?", "scenario": "A customer walks into the store and immediately heads toward the Free People section. They appear to be browsing casually."}, {"guidance": "Ask ''Have you ever shopped our shoes before?'' Since they seem to be struggling, likely they''ll say no or need help. Demonstrate how to pull on the book to open the shoe wall cabinet and explain the open stock system.", "question": "What''s your approach and opening script?", "scenario": "A customer is looking at shoes and trying to find their size. They seem frustrated and are having trouble with the shoe wall."}, {"guidance": "Since they know the brand, use the ''YES'' script: ''Great! Then you know they''re manufactured by Level 99 so you get the same quality jean without the price of Level 99. Which style is your favorite?'' Listen to their response, then offer to help them try on their preferred style or show new arrivals.", "question": "How do you continue the conversation?", "scenario": "A customer says they''ve heard of Jacob Davis jeans and have tried them before, mentioning they love the quality."}], "objectives": ["Greet every customer within 20 seconds using our welcoming approach", "Confidently introduce each product area using appropriate scripts", "Adapt conversations based on customer familiarity with products", "Suggest best-sellers, new arrivals, or personal favorites in each section"], "description": "Master the art of customer engagement through structured scripts for each product area in our boutique. Learn how to greet customers warmly, introduce product sections effectively, and guide customers through their shopping experience with confidence.", "markdownContent": "# Customer Engagement & Product Area Scripts\n\n## Welcome & Initial Greeting\n\n### The 20-Second Rule\nEvery guest must be greeted within 20 seconds of entering the store at either entrance.\n\n**Opening Script:**\n*\"Hey, how are you today?\"*\n\nFollow up with a helpful/inspiring question:\n- *\"Are you shopping for an event in particular?\"*\n- *\"We have some great pieces that would look great on you, would it be alright for me to pull a few down and set up a dressing room for you?\"*\n\n## Product Area Introductions\n\n### Free People Area\n**Opening:** *\"Did you know that we''re a Free People Shop-in-Shop?\"*\n\n**If customer says NO:**\n*\"Well a Free People Shop-in-Shop means that we carry such a large selection of Free People items that we are considered our own Free People store. We sell not only clothing, but shoes and intimates as well. However, we are locally owned and operated store not associated with Urban Outfitters stores.\"*\n\n**If customer says YES:**\n*\"Well great! That means you know we carry a large selection of Free People items including shoes and intimates. If you have trouble finding anything, just let me know.\"*\n\n**Always:** Suggest a best-seller, new arrival, or personal favorite from the FP area.\n\n### Shoes Section\n**Opening:** *\"Have you ever shopped our shoes before?\"*\n\n**If customer says NO:**\n*\"Well just so you know, all our shoes are on the floor and open stock meaning you are welcome to browse for your own sizes near the style you like, but I''m here to assist you if needed. Also, our shoe wall hides all the extra sizes, so be sure to pull on the book to find your size.\"*\n\n**Demonstrate** how to open the cabinet.\n\n**If customer says YES:**\n*\"Fantastic. That means you know all our sizes on the floor and to pull on the book to find the size you need on the shoe wall. If you need help finding your size or have any questions, be sure to let me know.\"*\n\n### Candle Area\n**Opening:** *\"Do you know about Aspen Bay candles?\"*\n\n**If customer says NO:**\n*\"Aspen Bay candles are actually made in Starkville. It''s a soy-based candle that smells fantastic and burn forever. The large candles will burn for over 80 hours!\"*\n\n**If customer says YES:**\nAsk: *\"Have you ever purchased one?\"*\n- **If YES:** *\"Well great! Then you know how awesome they are. Libby''s favorite scent is Sueded Tobacco so we try to always burn one at the register. What''s your favorite scent?\"*\n- **If NO:** *\"Well be sure to check out our selection. Libby''s favorite scent is Sueded Tobacco so we burn one at the register a lot. It smells up the entire store!! My favorite scent is _______ and that''s what I use at home. Which scent do you like most?\"*\n\n### Jacob Davis Jeans Area\n**Opening:** *\"Have you heard of Jacob Davis jeans before?\"*\n\n**If customer says NO:**\n*\"Just so you know, Jacob Davis jeans are manufactured in the same place as Level 99 jeans, so you get the same quality jean without the same price tag. They''re super soft, pretty stretchy, and most styles come in a 31\" inseam. Would you like to try a pair on?\"*\n\n**If customer says YES:**\n*\"Great! Then you know they''re manufactured by Level 99 so you get the same quality jean without the price of Level 99. Which style is your favorite? We try to always keep styles and sizes fully stocked. Would you like to try a pair on?\"*\n\n### Jewelry Area\n**Opening:** *\"Did you know that we carry a large selection of handmade jewelry?\"*\n\n**If customer says NO:**\n*\"Oh, well let me tell you about a few of our handmade lines.\"*\n\nTake customer towards jewelry cases and explain:\n- **Nakamol:** Line from Chicago, known for wrap bracelets, uses real leather and semi-precious stones\n- **Flea Market Girl:** Combines raw minerals, semi-precious stones, bronze, leather, and brass\n- **Lo Lady:** Made by local Jackson artist in Fondren, vintage-inspired upcycled pieces\n\nPoint out necklace and earring locations, then highlight a favorite, best-seller, or must-have.\n\n### Dressing Room Protocol\n**Opening:** *\"Do you follow us on Instagram or Facebook?\"*\n\nIntroduce social shopping based on their response:\n- Explain the 10% off benefit for signing up\n- Show them the form on the clipboard\n- Reassure about credit card security\n\n## Key Success Factors\n\n1. **Timing:** Always greet within 20 seconds\n2. **Adaptability:** Listen to customer responses and adapt accordingly\n3. **Product Knowledge:** Know your best-sellers, new arrivals, and personal favorites\n4. **Demonstration:** Show, don''t just tell (shoe wall, jewelry cases)\n5. **Personal Touch:** Share favorite scents, styles, or recommendations\n6. **Follow Through:** Always offer assistance and next steps\n\n## Remember: Professional & Warm\nOur brand voice should always feel welcoming and knowledgeable without being pushy. We''re here to help customers discover pieces they''ll love while sharing our expertise about the unique brands we carry.", "estimatedMinutes": 25}', '["a14c55ac-bfdc-4c40-8882-7dc586aeeb93"]', 'in_review', NULL, '46870047', '2026-04-14 18:57:56.653389', '2026-04-14 18:57:56.653389'),
	('c4758366-1bff-4431-a789-f125574107dc', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Engagement and Needs Assessment Process', '{"role": "New Associate", "tags": ["customer service", "relationship building", "needs assessment"], "steps": [{"type": "action", "order": 1, "title": "Warm Greeting and Relationship Building", "description": "Greet every customer within 30 seconds of entering with a genuine smile and welcoming phrase like ''Good morning! Welcome to Our Store.'' Follow with appropriate small talk about the weather, compliment their style, or mention current trends to create a comfortable atmosphere.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Listen and Assess Customer Needs", "description": "Ask open-ended questions such as ''What brings you in today?'' or ''What kind of occasion are you shopping for?'' Give customers 70% of the talking time while you actively listen to understand their specific requirements, preferences, and budget.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Customer Response Type", "description": "Determine next steps based on how clearly the customer expresses their needs", "decisionOptions": [{"action": "Present 2-3 targeted options that match their criteria", "condition": "If customer has specific needs"}, {"action": "Offer assistance and mention current promotions while giving them space", "condition": "If customer is browsing"}, {"action": "Ask lifestyle questions to better understand their preferences", "condition": "If customer seems uncertain"}]}, {"type": "action", "order": 4, "title": "Present Solutions Focused on Customer Value", "description": "Show items that meet their stated needs while explaining specific benefits and value. Highlight what makes each piece special, how it fits their lifestyle, and why Our Store''s selection stands out from competitors.", "decisionOptions": null}], "title": "Customer Engagement and Needs Assessment Process", "summary": "A comprehensive approach to greeting customers, building rapport, and understanding their needs to provide exceptional personalized service."}', '["dbad453e-938d-4762-9257-419abbfd73f6"]', 'in_review', NULL, '46870047', '2026-04-14 18:58:25.659348', '2026-04-14 18:58:25.659348'),
	('77031929-687f-4602-9deb-11ea3cfa7f83', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Sales Process and Objection Handling Protocol', '{"role": "Lead", "tags": ["sales process", "objection handling", "closing techniques"], "steps": [{"type": "action", "order": 1, "title": "Product Knowledge Verification", "description": "Before engaging with customers, verify you know current promotions, pricing for regular inventory items, and key product features. Update yourself on any new arrivals or special offers at the start of each shift.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Paced Product Presentation", "description": "Present items at the customer''s pace, avoiding rushing them to purchase. Allow time for browsing, trying on items, and consideration. Focus on showing rather than telling by demonstrating product benefits.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Handle Customer Objections", "description": "Address customer concerns appropriately based on the type of objection raised", "decisionOptions": [{"action": "Acknowledge their preference and immediately show alternative styles that better match their taste", "condition": "If customer dislikes style/fit"}, {"action": "Highlight value proposition and suggest similar items at different price points", "condition": "If customer mentions price concerns"}, {"action": "Respect their timeline and offer to hold items while suggesting they continue browsing", "condition": "If customer needs time to decide"}]}, {"type": "action", "order": 4, "title": "Natural Closing Process", "description": "Wait for customer buying signals before suggesting purchase. Look for cues like asking about return policies, checking themselves in the mirror repeatedly, or asking about availability in other sizes.", "decisionOptions": null}], "title": "Sales Process and Objection Handling Protocol", "summary": "Structured approach to managing the sales process from product presentation through closing, including proper objection handling and pacing."}', '["dbad453e-938d-4762-9257-419abbfd73f6"]', 'in_review', NULL, '46870047', '2026-04-14 18:58:25.665698', '2026-04-14 18:58:25.665698'),
	('7c116af5-fb81-4e55-9a09-607b50d4e2af', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Building Customer Connections: Avoiding Common Sales Pitfalls', '{"role": "New Associate", "title": "Building Customer Connections: Avoiding Common Sales Pitfalls", "exercises": [{"guidance": "This violates mistakes #1, #2, and #3. Better approach: Greet warmly, ask what they''re looking for, and respect their interest in clearance items while being helpful about their actual needs.", "question": "What mistakes are being made in this approach? How would you handle this situation better?", "scenario": "A customer walks in and immediately heads to the clearance rack. You approach and say, ''Those clearance items are all final sale, but we have much better quality pieces over here in our new arrivals.''"}, {"guidance": "Ask specific questions about what they don''t like about each dress, listen to their concerns, and use that information to suggest better alternatives that address their specific preferences.", "question": "How could you better handle this objection and turn it into a sales opportunity?", "scenario": "A customer tries on three dresses and says ''I''m not sure about any of these.'' You respond, ''Well, the blue one is our most popular style and it''s on sale today.''"}, {"guidance": "This is the perfect time for add-ons. Consider suggesting complementary items like blouses, accessories, or shoes that would complete their work wardrobe while they''re excited about their purchase.", "question": "How can you maximize this sale opportunity without being pushy?", "scenario": "A customer has decided to purchase a blazer for work. As you''re walking to the register, what should you be thinking about?"}], "objectives": ["Identify the 10 common sales mistakes that hinder customer relationships", "Apply customer-focused selling techniques that prioritize relationship building", "Demonstrate effective listening and needs assessment skills", "Practice proper timing for closing sales and offering add-ons"], "description": "Learn to recognize and avoid the 10 most common mistakes that can negatively impact customer experience and sales success at Our Store.", "markdownContent": "# Building Customer Connections: Avoiding Common Sales Pitfalls\n\n## Welcome to Our Store Sales Excellence\n\nAt Our Store, we believe that exceptional customer service begins with understanding what *not* to do. Every interaction you have with a customer either enhances or diminishes their experience with our brand. This module will help you recognize and avoid the most common pitfalls that can turn a potential sale into a missed opportunity.\n\n## The 10 Common Sales Mistakes to Avoid\n\n### 1. Failing to Build Relationships\n**The Mistake:** Jumping straight into product recommendations without connecting with the customer.\n\n**The Solution:** Start with a warm, genuine greeting. A simple \"Good morning! How''s your day going?\" or comment about the weather creates an open, friendly atmosphere that makes customers feel welcome.\n\n### 2. Not Discovering Customer Requirements\n**The Mistake:** Assuming you know what the customer wants without asking.\n\n**The Solution:** Ask thoughtful questions like \"What brings you in today?\" or \"What kind of look are you going for?\" Understanding their needs guides your recommendations.\n\n### 3. Pushing Your Own Agenda\n**The Mistake:** Showing customers what you think they should buy instead of what they actually want.\n\n**The Solution:** Listen to their preferences and guide them toward items that match their expressed needs and style.\n\n### 4. Dominating the Conversation\n**The Mistake:** Talking too much and not giving customers space to express themselves.\n\n**The Solution:** Follow the 70/30 rule—customers should be talking 70% of the time, you 30%. Ask open-ended questions and listen actively.\n\n### 5. Telling Instead of Selling\n**The Mistake:** Lecturing about product features without connecting to customer benefits.\n\n**The Solution:** Listen first, then explain how specific features address their stated needs. \"Since you mentioned wanting versatile pieces, this blazer can work for both office and weekend looks.\"\n\n### 6. Lacking Product and Pricing Knowledge\n**The Mistake:** Not knowing current promotions, pricing, or product details.\n\n**The Solution:** Stay updated on all promotions, regular pricing, and product features. Customers expect you to be the expert on Our Store''s offerings.\n\n### 7. Failing to Create Value\n**The Mistake:** Not differentiating Our Store''s products and service from competitors.\n\n**The Solution:** Highlight what makes our pieces special—quality, styling, exclusivity, or how they solve the customer''s specific fashion challenges.\n\n### 8. Rushing the Sale\n**The Mistake:** Pushing customers to purchase before they''re ready, especially right after trying items on.\n\n**The Solution:** Give customers time to consider. After they try items on, let them browse and suggest complementary pieces. Building excitement is better than creating pressure.\n\n### 9. Poorly Handling Objections\n**The Mistake:** Getting defensive or giving up when customers express concerns about style, fit, or price.\n\n**The Solution:** View objections as opportunities to better understand their needs. If they don''t like a particular style, ask what specifically they''d prefer and offer alternatives.\n\n### 10. Missing Add-On Opportunities\n**The Mistake:** Stopping the sale process once the main item is selected.\n\n**The Solution:** When customers are excited about their main purchase, they''re most open to accessories and complementary pieces. Suggest items that complete their look.\n\n## Putting It All Together: The Our Store Approach\n\nRemember, successful selling at Our Store is about creating a positive, pressure-free experience where customers feel heard, valued, and excited about their purchases. When you avoid these common mistakes, you naturally create the warm, professional atmosphere that reflects our brand values.\n\n## Key Takeaways\n\n- Build genuine connections before selling\n- Listen more than you speak\n- Focus on customer needs, not your agenda\n- Know your products and promotions inside and out\n- Give customers time and space to make decisions\n- Handle objections as opportunities to help\n- Maximize every sale with thoughtful add-on suggestions", "estimatedMinutes": 25}', '["dbad453e-938d-4762-9257-419abbfd73f6"]', 'in_review', NULL, '46870047', '2026-04-14 18:58:58.219163', '2026-04-14 18:58:58.219163'),
	('cd2d8373-0d2c-4950-906e-a232d90bb60e', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Using Power Words in Customer Interactions', '{"role": "New Associate", "tags": ["sales", "customer service", "communication", "training"], "steps": [{"type": "action", "order": 1, "title": "Open with ''You'' to personalize the conversation", "description": "Begin customer interactions by using ''You'' early in your greeting or presentation. Example: ''You''re going to love our new collection'' or ''This style would look amazing on you.'' This makes the conversation feel more personal and engaging.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Identify customer needs and motivations", "description": "Listen to what the customer is looking for and observe their behavior to determine which power words will resonate most. Pay attention to whether they mention comfort, style, occasions, or budget concerns.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Select appropriate power words based on customer needs", "description": "Choose power words that align with customer motivations", "decisionOptions": [{"action": "Use ''New'' and ''Discover'' - ''Discover our newest arrivals that everyone will love''", "condition": "If customer seeks style/trends"}, {"action": "Use ''Guarantee'' and ''Proven'' - ''This proven style comes with our satisfaction guarantee''", "condition": "If customer is hesitant about purchase"}, {"action": "Use ''Save'' and ''Results'' - ''You''ll save money while getting amazing results with this versatile piece''", "condition": "If customer mentions budget"}]}, {"type": "action", "order": 4, "title": "Incorporate multiple power words naturally", "description": "Weave 2-3 power words into your product presentation. Example: ''You''re going to love how this proven style gives you results that save you time getting ready each morning.'' Ensure the language flows naturally and doesn''t sound forced.", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Close with emotional connection", "description": "End your presentation using ''Love'' to create emotional attachment. Example: ''Your friends are going to love this look on you'' or ''You''ll love how confident this makes you feel.''", "decisionOptions": null}], "title": "Using Power Words in Customer Interactions", "summary": "A step-by-step guide for incorporating the 10 most powerful sales words into customer conversations to increase engagement and sales effectiveness."}', '["00853836-ddb7-42c2-ac98-ae57809921c2"]', 'in_review', NULL, '46870047', '2026-04-14 18:59:30.185948', '2026-04-14 18:59:30.185948'),
	('d287fc3a-06d0-434c-92fd-17e3639dcaf8', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Training Team Members on Power Word Implementation', '{"role": "Lead", "tags": ["training", "coaching", "team development", "sales techniques"], "steps": [{"type": "action", "order": 1, "title": "Conduct power words training session", "description": "Schedule a 30-minute training session to introduce the 10 power words. Explain the psychology behind each word and provide 2-3 example phrases for each word that associates can use with customers.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Demonstrate through role-playing exercises", "description": "Create scenarios where associates practice using power words in different customer situations. Have them practice opening conversations, handling objections, and closing sales using the power words naturally.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Observe associates during customer interactions", "description": "Shadow associates during actual customer interactions to observe their use of power words. Take notes on which words they use effectively and which opportunities they miss.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Provide targeted coaching based on observation", "description": "Determine coaching approach based on associate''s performance", "decisionOptions": [{"action": "Provide positive reinforcement and suggest advanced techniques", "condition": "If associate uses words naturally and effectively"}, {"action": "Practice specific scenarios and provide phrase examples", "condition": "If associate struggles with natural integration"}, {"action": "Create reminder card and schedule additional practice sessions", "condition": "If associate forgets to use power words"}]}, {"type": "action", "order": 5, "title": "Track and review progress weekly", "description": "Monitor associate progress by observing interactions and tracking sales metrics. Provide weekly feedback sessions to reinforce successful power word usage and address areas for improvement.", "decisionOptions": null}], "title": "Training Team Members on Power Word Implementation", "summary": "A structured approach for training and coaching associates on effectively using the 10 power words to improve sales performance and customer engagement."}', '["00853836-ddb7-42c2-ac98-ae57809921c2"]', 'in_review', NULL, '46870047', '2026-04-14 18:59:30.194189', '2026-04-14 18:59:30.194189'),
	('1faf40c9-7f64-4a0d-ac67-2a16411dbda9', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Analyzing Power Word Effectiveness and Sales Impact', '{"role": "Manager", "tags": ["analytics", "performance tracking", "sales metrics", "team management"], "steps": [{"type": "action", "order": 1, "title": "Establish baseline metrics before implementation", "description": "Record current sales metrics including average transaction value, conversion rate, and customer satisfaction scores before implementing power word training. This will serve as your comparison benchmark.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Create tracking system for power word usage", "description": "Develop a simple tracking method to monitor which associates are consistently using power words and in what contexts. Use weekly observation sheets or customer feedback to gather this data.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Monitor sales performance indicators", "description": "Track key metrics weekly including sales per associate, average transaction value, conversion rates, and return rates. Compare these metrics to your established baseline to measure improvement.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Evaluate effectiveness and adjust strategy", "description": "Assess results after 4-6 weeks of implementation", "decisionOptions": [{"action": "Continue current approach and expand training to advanced techniques", "condition": "If metrics show significant improvement"}, {"action": "Identify specific areas for additional training and coaching", "condition": "If metrics show modest improvement"}, {"action": "Reassess training methods and provide intensive retraining sessions", "condition": "If metrics show no improvement"}]}, {"type": "action", "order": 5, "title": "Report results and plan next steps", "description": "Compile monthly reports showing the impact of power word implementation on sales and customer satisfaction. Share successful examples with the team and identify top performers to mentor others. Plan ongoing training sessions to maintain momentum.", "decisionOptions": null}], "title": "Analyzing Power Word Effectiveness and Sales Impact", "summary": "A systematic approach for managers to measure the effectiveness of power word implementation and its impact on store sales performance and customer satisfaction."}', '["00853836-ddb7-42c2-ac98-ae57809921c2"]', 'in_review', NULL, '46870047', '2026-04-14 18:59:30.201755', '2026-04-14 18:59:30.201755'),
	('b94300b4-15be-4ad5-8b23-9f4606ceac52', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Mastering the 10 Power Words for Sales Excellence', '{"role": "New Associate", "title": "Mastering the 10 Power Words for Sales Excellence", "exercises": [{"guidance": "Ideal response should include power words like ''You,'' ''Proven,'' ''Save,'' and ''Guarantee.'' Example: ''You deserve to feel confident in your new role, and this proven style will save you from needing multiple blazers. I guarantee this investment piece will become your go-to for years to come.''", "question": "Using at least 3 power words, how would you help this customer feel confident about their investment?", "scenario": "A customer is browsing blazers for a new job but seems hesitant about the price point of a high-quality piece."}, {"guidance": "Focus on ''Discover,'' ''Love,'' ''New,'' and ''You.'' Example: ''You have the perfect style to pull this off! Let''s discover how amazing you look in this new trend - I love how it brings out your personality. You''ll discover it''s not too bold at all, it''s just right.''", "question": "How would you use power words to help them embrace trying something new?", "scenario": "A customer is looking at a trendy dress but mentions they''re not sure if it''s too bold for them."}, {"guidance": "Use ''Results,'' ''Guarantee,'' ''Love,'' ''Proven,'' and ''You.'' Example: ''You want guaranteed results for such an important event. This proven silhouette delivers the elegant look you''re after - you''re going to love how confident and beautiful you feel. I guarantee you''ll get compliments all night.''", "question": "Which power words would help address their desire for perfection and how would you use them?", "scenario": "A customer is shopping for a special occasion outfit and mentions they want to make sure they look perfect."}], "objectives": ["Identify and memorize the 10 most powerful words for retail sales", "Understand the psychological impact of each power word on customer behavior", "Apply power words naturally in customer conversations to increase sales effectiveness", "Use power words to overcome common sales objections and build customer confidence"], "description": "Learn to use ten psychologically powerful words that increase sales effectiveness and create more personal, compelling customer interactions at Our Store.", "markdownContent": "# Mastering the 10 Power Words for Sales Excellence\n\n## Welcome to Our Store''s Power Words Training\n\nAs a fashion boutique associate, your words have the power to transform a casual browser into a loyal customer. This module will equip you with ten scientifically-backed words that tap into fundamental human psychology to create more engaging, effective sales conversations.\n\n## Why Power Words Matter\n\nEvery customer who walks through our doors is looking for solutions, experiences, and connections. The right words at the right moment can:\n- Make conversations feel more personal and engaging\n- Address underlying customer concerns and motivations\n- Build trust and confidence in their purchase decisions\n- Create emotional connections with our products\n\n## The 10 Power Words\n\n### 1. **YOU**\n**Why it works:** Makes conversations personal and customer-focused\n\n**How to use it:** Start presentations and recommendations with \"You\" to immediately engage the customer.\n- \"You would look amazing in this dress\"\n- \"This style was designed for someone with your fashion sense\"\n- \"You deserve something special for that event\"\n\n### 2. **RESULTS**\n**Why it works:** Customers seek solutions to problems and answers to questions\n\n**How to use it:** Connect products to outcomes the customer desires.\n- \"This jacket delivers the professional results you''re looking for\"\n- \"You''ll see results immediately - it''s so flattering\"\n- \"The results speak for themselves when you wear this outfit\"\n\n### 3. **HEALTH**\n**Why it works:** Everyone cares about their wellbeing and body\n\n**How to use it:** Highlight comfort, fit, and wellness benefits.\n- \"These shoes promote foot health with their ergonomic design\"\n- \"This fabric is healthy for your skin - it''s completely breathable\"\n- \"It''s healthy to invest in quality pieces that make you feel confident\"\n\n### 4. **GUARANTEE**\n**Why it works:** Reduces purchase anxiety and fear of making mistakes\n\n**How to use it:** Address concerns about fit, quality, or satisfaction.\n- \"We guarantee you''ll love how this fits\"\n- \"Our alteration guarantee ensures the perfect fit\"\n- \"I guarantee this will become your go-to piece\"\n\n### 5. **DISCOVER**\n**Why it works:** Appeals to natural curiosity and desire to be first with trends\n\n**How to use it:** Create excitement about new arrivals and unique pieces.\n- \"Discover this season''s must-have trend\"\n- \"You''ll discover how versatile this piece really is\"\n- \"Let''s discover the perfect look for your lifestyle\"\n\n### 6. **LOVE**\n**Why it works:** Creates emotional connection and anticipates satisfaction\n\n**How to use it:** Build enthusiasm and emotional attachment.\n- \"You''re going to love how this makes you feel\"\n- \"People love complimenting customers wearing this designer\"\n- \"You''ll love the way this transitions from day to night\"\n\n### 7. **PROVEN**\n**Why it works:** Removes fear of trying something new or different\n\n**How to use it:** Combine with testimonials and guarantees for maximum impact.\n- \"This silhouette is proven to be universally flattering\"\n- \"It''s a proven wardrobe essential that never goes out of style\"\n- \"This brand has a proven track record for quality and durability\"\n\n### 8. **SAFETY**\n**Why it works:** Appeals to fundamental needs for security and protection\n\n**How to use it:** Address concerns about investment, quality, and appropriateness.\n- \"It''s always safe to invest in classic pieces like this\"\n- \"This is a safe choice that will work for multiple occasions\"\n- \"The safety of knowing you look perfectly put-together\"\n\n### 9. **SAVE**\n**Why it works:** Everyone wants to save money, time, and effort\n\n**How to use it:** Show value beyond just price.\n- \"Save time getting ready with this versatile piece\"\n- \"Save money by investing in quality that lasts\"\n- \"This will save you from multiple shopping trips - it goes with everything\"\n\n### 10. **NEW**\n**Why it works:** Satisfies desire to stay current and be ahead of trends\n\n**How to use it:** Create urgency and highlight freshness.\n- \"This new collection just arrived from Paris\"\n- \"Try this new styling approach - it''s very now\"\n- \"New arrivals like this sell quickly\"\n\n## Putting It All Together\n\n### Natural Integration\nThe key to using power words effectively is making them sound natural and genuine. Practice weaving them into your regular conversation style rather than forcing them.\n\n### Combination Power\nCombine multiple power words for greater impact:\n- \"You''ll love the proven results this new style delivers\"\n- \"Discover how this guaranteed wardrobe essential will save you time\"\n\n### Reading Your Customer\nPay attention to what motivates each individual customer and emphasize the power words that resonate most with their needs and personality.\n\n## Key Reminders\n- Use \"You\" early and often to personalize every interaction\n- Address the emotional and practical benefits customers seek\n- Build confidence with \"Guarantee,\" \"Proven,\" and \"Safety\"\n- Create excitement with \"Discover,\" \"Love,\" and \"New\"\n- Always connect power words to genuine product benefits\n\n## Your Mission\nAs an Our Store associate, you now have the tools to create more engaging, effective conversations that help customers feel confident, excited, and satisfied with their choices. Practice these power words daily, and watch your sales effectiveness grow while providing exceptional customer experiences.", "estimatedMinutes": 25}', '["00853836-ddb7-42c2-ac98-ae57809921c2"]', 'in_review', NULL, '46870047', '2026-04-14 19:00:09.491542', '2026-04-14 19:00:09.491542'),
	('a51c2b73-7551-4b49-b5ac-7336b8a8d938', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Approach and Engagement Process', '{"role": "New Associate", "tags": ["customer service", "sales approach", "rapport building"], "steps": [{"type": "action", "order": 1, "title": "Prepare Your Approach", "description": "Maintain a positive attitude and carry a relevant prop (such as a product sample, accessory, or styling tool) when approaching customers. This gives you a natural conversation starter and professional appearance.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Make Initial Contact", "description": "Approach the customer with a personal remark that demands a positive answer to put them at ease. For example, ''That color looks amazing on you!'' or ''You have great timing - we just got this collection in!'' Avoid saying ''Can I help you?'' as it often receives a defensive response.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Engage and Withdraw", "description": "After your initial positive interaction, give the customer space to browse. Say something like ''I''ll let you take a look around, and I''ll check back in a few minutes to see how you''re doing.''", "decisionOptions": null}, {"type": "action", "order": 4, "title": "Return and Build Rapport", "description": "Return within 3-5 minutes to continue building rapport. Ask open-ended questions that cannot be answered with ''no,'' such as ''What kind of occasion are you shopping for?'' or ''What style are you drawn to today?''", "decisionOptions": null}, {"type": "decision", "order": 5, "title": "Decision: Customer Engagement Level", "description": "Assess the customer''s level of interest and engagement to determine next steps.", "decisionOptions": [{"action": "Continue with product consultation and styling advice", "condition": "If customer is engaged and asking questions"}, {"action": "Offer assistance with specific needs and check back later", "condition": "If customer needs more time"}, {"action": "Provide detailed product knowledge and suggest complementary pieces", "condition": "If customer shows interest in specific items"}]}], "title": "Customer Approach and Engagement Process", "summary": "A structured approach to greeting customers, building rapport, and creating a comfortable shopping environment that encourages engagement and sales."}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:00:44.972978', '2026-04-14 19:00:44.972978'),
	('6767977f-e752-4a77-976e-a25a97bbd001', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Inventory Management and Alternative Solutions', '{"role": "Lead", "tags": ["inventory management", "problem solving", "customer retention"], "steps": [{"type": "action", "order": 1, "title": "Know Your Stock", "description": "Maintain thorough knowledge of current inventory levels, including sizes, colors, and quantities. Regularly check stock levels and avoid overselling limited items. Update your knowledge daily through inventory reports and floor checks.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Check for Item Availability", "description": "When a customer requests a specific item, immediately check both floor inventory and back stock. Use the POS system to verify exact availability including all sizes and color options.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Item Availability Status", "description": "Determine the availability status of the requested item to provide appropriate next steps.", "decisionOptions": [{"action": "Retrieve the item and continue with the sale", "condition": "If item is available in requested size/color"}, {"action": "Present available options and explain differences", "condition": "If item is available in different size/color only"}, {"action": "Proceed to alternative solution process", "condition": "If item is completely out of stock"}]}, {"type": "action", "order": 4, "title": "Never Return Empty-Handed", "description": "When the exact item is unavailable, present similar alternatives that meet the customer''s needs. Select items with comparable style, price point, or function. Explain the benefits and unique features of the alternative options.", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Offer Additional Solutions", "description": "Contact other store locations to locate the item, or offer to special order the item if available through the system. Provide clear timelines for availability and follow-up procedures.", "decisionOptions": null}, {"type": "action", "order": 6, "title": "Document and Follow Up", "description": "Record customer contact information and item details for future follow-up. If special ordering or locating from other stores, provide expected delivery dates and contact the customer when the item arrives.", "decisionOptions": null}], "title": "Inventory Management and Alternative Solutions", "summary": "A comprehensive process for handling out-of-stock situations while maintaining sales opportunities and customer satisfaction through alternative solutions."}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:00:44.979468', '2026-04-14 19:00:44.979468'),
	('637386c3-0e9c-4ce5-95c4-e155c2949297', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Sales Completion and Customer Follow-Up', '{"role": "Manager", "tags": ["sales completion", "upselling", "customer follow-up", "relationship building"], "steps": [{"type": "action", "order": 1, "title": "Present Additional Products", "description": "At the close of the primary sale, present complementary products and accessories that enhance the customer''s purchase. Focus on items that complete the look or add versatility to their selection.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Provide Product Knowledge", "description": "Share comprehensive information about the merchandise including price points, construction details, care instructions, and how it compares to other brands. Demonstrate your expertise to build customer confidence.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Complete Transaction with Personal Touch", "description": "Process the sale efficiently while maintaining personal connection. Thank the customer by name during the transaction and ensure they have all necessary information about their purchase including care instructions and return policy.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Follow-Up Method", "description": "Determine the appropriate follow-up method based on the sale value and customer relationship potential.", "decisionOptions": [{"action": "Send personalized thank you note the following day", "condition": "For high-value purchases or new customers"}, {"action": "Make note in customer profile for future reference and personal service", "condition": "For regular customers"}, {"action": "Schedule follow-up call when items are ready", "condition": "For special orders or alterations"}]}, {"type": "action", "order": 5, "title": "Send Thank You Note", "description": "For appropriate sales, send a brief, personalized thank you note the day after the purchase. Include the customer''s name, reference their specific purchase, and express appreciation for their business. This reinforces the personal shopping experience.", "decisionOptions": null}], "title": "Sales Completion and Customer Follow-Up", "summary": "A systematic approach to maximizing sales through add-on suggestions, proper checkout procedures, and post-sale customer appreciation to build long-term relationships."}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:00:44.987632', '2026-04-14 19:00:44.987632'),
	('94ca9326-de97-40c3-aa0d-e1da7330520c', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Mastering the 12 Principles of Exceptional Sales Performance', '{"role": "New Associate", "title": "Mastering the 12 Principles of Exceptional Sales Performance", "exercises": [{"guidance": "Ideal approach: Carry a complementary accessory (like a scarf or jewelry) as your prop. Make a positive personal comment such as ''You''re looking at some of our most popular pieces!'' Allow her to respond, then offer to help by asking an opening question like ''What type of occasion are you shopping for?'' This puts her at ease while opening dialogue about her specific needs.", "question": "Using the principles learned, how would you approach this customer to create a positive interaction?", "scenario": "A customer is browsing our dress section, picking up items but putting them back. She looks slightly overwhelmed and hasn''t made eye contact with any staff."}, {"guidance": "Never return empty-handed! Show her similar styles from other designers in the same size, explain the benefits of these alternatives, and offer to check other store locations for the original item. If she''s interested but not ready to decide, suggest special ordering the original item and take her contact information for follow-up. This demonstrates commitment to her needs beyond the immediate sale.", "question": "How would you handle this situation to potentially save the sale and maintain customer satisfaction?", "scenario": "A customer asks for a specific designer top in size medium, but you know it''s sold out. You can see she''s disappointed and seems ready to leave the store."}, {"guidance": "Present complementary accessories that enhance her outfit (jewelry, handbag, or jacket), ask about upcoming occasions where she might need additional pieces, complete the sale warmly using her name, and plan for follow-up contact. This approach adds value for her while increasing transaction size and building a foundation for future visits.", "question": "What steps should you take to maximize this positive interaction and potentially increase the sale value?", "scenario": "You''ve helped a customer find the perfect outfit - a dress and shoes. She''s ready to purchase and seems very happy with her selections."}], "objectives": ["Apply proven customer approach and engagement strategies to build rapport effectively", "Demonstrate comprehensive product knowledge and inventory management skills", "Implement professional follow-up practices to enhance customer relationships", "Maintain a positive, solution-focused mindset in all customer interactions"], "description": "Learn the fundamental practices that distinguish top-performing sales associates, from customer engagement techniques to product expertise and follow-up excellence.", "markdownContent": "# Mastering the 12 Principles of Exceptional Sales Performance\n\nWelcome to Our Store''s comprehensive sales training! As a fashion boutique, we pride ourselves on providing exceptional customer experiences while achieving outstanding sales results. This module will equip you with the 12 proven principles that our top performers use to consistently exceed their goals.\n\n## The Foundation: Your Mindset and Environment\n\n### Principle 1: Cultivate a Positive Attitude\nYour attitude is your most powerful tool. When challenges arise, focus your energy on solutions rather than complaints. This positive approach not only improves your own experience but radiates to customers, creating a more welcoming atmosphere.\n\n### Principle 2: Maintain Store Standards\nA clean, organized store environment directly impacts sales performance. When merchandise is well-presented and easy to find, customers feel more confident in their purchases and are more likely to browse longer.\n\n## Customer Engagement Excellence\n\n### Principle 3: Proactive Customer Interaction\nSuccessful associates understand that every customer interaction is an opportunity. Make it your goal to speak with more customers throughout your shift.\n\n### Principle 4: Master the Warm Approach\nCustomers often feel defensive when entering a store. Instead of asking \"Can I help you?\" try personal remarks that invite positive responses, such as:\n- \"That color looks wonderful on you!\"\n- \"You have excellent taste - that''s one of our newest pieces!\"\n- \"What a beautiful day to find something special!\"\n\n### Principle 5: The Strategic Prop Technique\nWhen approaching a customer, carry a relevant item (your \"prop\") that relates to what they''re browsing. Make your initial contact brief to allow browsing time, then return within a few minutes to continue building rapport.\n\n### Principle 6: Ask Opening Questions\nFrame questions that invite detailed responses rather than simple yes/no answers:\n- \"What occasions are you shopping for today?\"\n- \"What styles make you feel most confident?\"\n- \"Which of these pieces speaks to you?\"\n\n## Product Expertise and Inventory Management\n\n### Principle 7: Know Your Inventory\nStay informed about stock levels and avoid overselling limited items. This knowledge helps you manage customer expectations and suggest alternatives proactively.\n\n### Principle 8: Never Return Empty-Handed\nWhen a specific item isn''t available, always present similar alternatives. This demonstrates your commitment to helping customers find what they need.\n\n### Principle 9: Master the Art of Add-Ons\nAt the close of each sale, present complementary products and accessories that enhance the customer''s purchase. This adds value for the customer while increasing transaction size.\n\n### Principle 10: Extend Your Reach\nWhen items are out of stock, check other store locations or suggest special ordering. This extra effort often turns a potential disappointment into a positive experience.\n\n### Principle 11: Become a Product Expert\nUnderstand every aspect of your merchandise:\n- Price points and value propositions\n- Construction quality and materials\n- Care instructions and longevity\n- How items compare to competitors\n- New arrivals and upcoming collections\n\n## Building Lasting Relationships\n\n### Principle 12: Personal Follow-Up\nAlways thank customers by name at the time of sale. Consider sending a brief, personal note the following day to reinforce their positive experience and encourage future visits.\n\n## Putting It All Together\n\nThese 12 principles work synergistically to create exceptional customer experiences while driving sales success. Remember, consistency is key - top performers apply these practices with every customer, every day.\n\nAs you implement these strategies, you''ll notice that selling becomes more natural and enjoyable. Your customers will feel genuinely cared for, leading to increased loyalty and referrals that benefit both you and Our Store.\n\n## Key Takeaways\n\n- Your positive attitude sets the tone for every customer interaction\n- Strategic questioning and genuine interest build stronger customer relationships\n- Product expertise enables you to provide valuable guidance and alternatives\n- Professional follow-up transforms one-time shoppers into loyal customers\n- Consistency in applying these principles separates good associates from great ones", "estimatedMinutes": 25}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:01:21.197121', '2026-04-14 19:01:21.197121'),
	('1f8c1a01-00b5-4ee5-9ac1-258c872e3213', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'task', 'Daily Sales Excellence Checklist', '{"role": "New Associate", "tasks": [{"order": 1, "title": "Start with a positive mindset", "isRequired": true, "description": "Take 2 minutes to set a positive attitude for the day and commit to maintaining it regardless of challenges", "estimatedMinutes": 2}, {"order": 2, "title": "Clean and organize assigned section", "isRequired": true, "description": "Ensure your designated area is spotless, properly merchandised, and visually appealing", "estimatedMinutes": 15}, {"order": 3, "title": "Review daily inventory highlights", "isRequired": true, "description": "Check what''s new, limited stock items, and featured products to discuss with customers", "estimatedMinutes": 10}, {"order": 4, "title": "Practice positive customer greetings", "isRequired": true, "description": "Use personal remarks that require positive responses instead of ''Can I help you?'' - focus on compliments or observations", "estimatedMinutes": 5}, {"order": 5, "title": "Prepare customer approach props", "isRequired": true, "description": "Select accessories or featured items to carry when approaching customers to create natural conversation starters", "estimatedMinutes": 5}, {"order": 6, "title": "Follow up on previous day''s customers", "isRequired": true, "description": "Send thank you notes to customers who made purchases yesterday, mentioning them by name", "estimatedMinutes": 15}], "title": "Daily Sales Excellence Checklist", "frequency": "daily", "description": "Essential daily tasks for new associates to build strong sales fundamentals and customer service skills"}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:01:39.80404', '2026-04-14 19:01:39.80404'),
	('6a6fa46e-f1c7-4e82-a5c8-81f417b376f1', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'task', 'Advanced Sales Performance Checklist', '{"role": "Lead", "tasks": [{"order": 1, "title": "Set daily sales targets and strategy", "isRequired": true, "description": "Review sales goals, identify opportunities, and plan approach for maximizing customer interactions", "estimatedMinutes": 10}, {"order": 2, "title": "Conduct store presentation audit", "isRequired": true, "description": "Ensure entire store meets high cleanliness and organization standards that drive sales performance", "estimatedMinutes": 20}, {"order": 3, "title": "Update product knowledge base", "isRequired": true, "description": "Study new arrivals, price points, construction details, and competitive comparisons to stay ahead of customer questions", "estimatedMinutes": 15}, {"order": 4, "title": "Plan alternative solutions for popular items", "isRequired": true, "description": "Identify similar products and special order options for anticipated out-of-stock situations", "estimatedMinutes": 10}, {"order": 5, "title": "Coach team on customer approach techniques", "isRequired": true, "description": "Observe and provide feedback on team members'' customer greeting methods and rapport-building skills", "estimatedMinutes": 20}, {"order": 6, "title": "Review and execute add-on sales strategies", "isRequired": true, "description": "Plan accessory and complementary product presentations for closing sales and increasing transaction values", "estimatedMinutes": 10}, {"order": 7, "title": "Manage customer follow-up system", "isRequired": true, "description": "Ensure all customer thank you notes are personalized and sent, track customer preferences for future visits", "estimatedMinutes": 15}], "title": "Advanced Sales Performance Checklist", "frequency": "daily", "description": "Comprehensive daily checklist for experienced team leads focused on maximizing sales outcomes and coaching others"}', '["d2316b75-9a96-4b5e-9990-a5c7bc9dd0a9"]', 'in_review', NULL, '46870047', '2026-04-14 19:01:39.811036', '2026-04-14 19:01:39.811036'),
	('6213f5ab-d829-4653-9f89-9f96069cc02f', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Greeting Protocol - Stop and Drop in 15', '{"role": "New Associate", "tags": ["customer service", "greeting", "first impression", "sales"], "steps": [{"type": "action", "order": 1, "title": "Monitor customer entry and movement", "description": "Stay alert to customers entering the store or approaching within 15 feet of your location. Begin the greeting sequence within 15 seconds of spotting them.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Stop current activity and make initial contact", "description": "Immediately stop what you are doing, make direct eye contact with the customer, and give them a genuine, welcoming smile to break the ice and show attentiveness.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Drop tasks and approach customer", "description": "Set aside your current work, take several steps toward the customer with open body language, offer a friendly ''Hi!'' and give a casual wave to create a warm welcome.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Assess customer response and next steps", "description": "Observe the customer''s reaction to determine appropriate follow-up approach", "decisionOptions": [{"action": "Continue with conversation and offer assistance", "condition": "If customer responds positively and makes eye contact"}, {"action": "Give them space while remaining available and approachable", "condition": "If customer seems busy or distracted"}, {"action": "Maintain friendly distance and let them know you''re available if needed", "condition": "If customer appears hesitant or overwhelmed"}]}], "title": "Customer Greeting Protocol - Stop and Drop in 15", "summary": "Establish positive first impressions by acknowledging and greeting customers within 15 seconds or 15 feet of their entrance or approach."}', '["43363e98-6ab7-47ad-b1b6-b4b147ccd668"]', 'in_review', NULL, '46870047', '2026-04-14 19:02:07.279199', '2026-04-14 19:02:07.279199'),
	('4f8bd399-4e2c-44e9-979d-568de44b19ae', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Training New Associates on Customer Greeting Standards', '{"role": "Lead", "tags": ["training", "coaching", "customer service", "team development"], "steps": [{"type": "action", "order": 1, "title": "Explain the Stop and Drop in 15 rule", "description": "Teach new associates the importance of the 20-second first impression window and demonstrate the three steps: recognize customers within 15 seconds/15 feet, stop and make eye contact with a smile, then drop tasks and approach with a friendly greeting.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Demonstrate proper greeting technique", "description": "Model the correct body language, eye contact, smile, and approach for new associates. Show examples of open posture, appropriate distance, and friendly verbal greetings.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Practice with role-playing scenarios", "description": "Have the new associate practice greeting different types of customers (rushed, browsing, hesitant) while you observe and provide feedback on timing, body language, and approach.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Monitor and provide feedback during shifts", "description": "Observe the associate''s greeting performance during actual customer interactions and provide coaching", "decisionOptions": [{"action": "Acknowledge good performance and reinforce positive behaviors", "condition": "If associate successfully follows the protocol"}, {"action": "Provide gentle correction and additional practice opportunities", "condition": "If associate misses timing or steps"}, {"action": "Offer encouragement and break down the steps into smaller, manageable parts", "condition": "If associate seems uncomfortable or nervous"}]}], "title": "Training New Associates on Customer Greeting Standards", "summary": "Train and coach new team members on the Stop and Drop in 15 rule to ensure consistent, positive customer first impressions across the store."}', '["43363e98-6ab7-47ad-b1b6-b4b147ccd668"]', 'in_review', NULL, '46870047', '2026-04-14 19:02:07.289019', '2026-04-14 19:02:07.289019'),
	('7734e018-8a57-428a-b0af-0a2f6534908d', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Monitoring Customer Service Standards and First Impressions', '{"role": "Manager", "tags": ["quality assurance", "customer service", "staff monitoring", "standards"], "steps": [{"type": "action", "order": 1, "title": "Conduct regular floor observations", "description": "Walk the sales floor during different shifts and peak times to observe how associates implement the Stop and Drop in 15 rule. Document timing, approach quality, and customer responses.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Track customer feedback on first impressions", "description": "Monitor customer reviews, feedback forms, and informal comments related to store greeting and initial service quality. Look for patterns or recurring issues.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Evaluate individual and team performance", "description": "Assess which associates consistently meet greeting standards and identify those who need additional support or training.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Implement corrective actions based on observations", "description": "Take appropriate action based on performance assessment results", "decisionOptions": [{"action": "Recognize and reward team performance, maintain current practices", "condition": "If standards are consistently met"}, {"action": "Arrange additional coaching sessions with leads and create improvement plans", "condition": "If specific associates need improvement"}, {"action": "Review training materials, adjust scheduling, or modify store layout to support better customer service", "condition": "If systemic issues are identified"}]}], "title": "Monitoring Customer Service Standards and First Impressions", "summary": "Ensure consistent implementation of greeting protocols across all staff and maintain high customer service standards that create positive first impressions."}', '["43363e98-6ab7-47ad-b1b6-b4b147ccd668"]', 'in_review', NULL, '46870047', '2026-04-14 19:02:07.308723', '2026-04-14 19:02:07.308723'),
	('6971a7c7-b146-4290-9638-1446959bc0bf', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Creating Memorable First Impressions: The Stop and Drop in 15 Rule', '{"role": "New Associate", "title": "Creating Memorable First Impressions: The Stop and Drop in 15 Rule", "exercises": [{"guidance": "Ideal response should include: 1) Immediately stopping the display work, 2) Making eye contact with the customer, 3) Giving a genuine smile, 4) Taking steps toward the customer, 5) Offering a friendly greeting like ''Hello! Welcome to Our Store!'' All within 15 seconds of noticing the customer.", "question": "Using the Stop and Drop in 15 rule, what specific actions would you take and in what order?", "scenario": "A customer enters the store while you''re organizing a display rack about 10 feet away from the entrance. You notice them looking around uncertainly."}, {"guidance": "Ideal response includes: Making eye contact with the new customer, giving them a welcoming smile and a friendly wave or nod to acknowledge them, then politely letting your current customer know you''ll be right back or that you see someone who needs assistance. The key is acknowledging the new customer within 15 seconds even if you can''t immediately approach them.", "question": "How would you apply the Stop and Drop in 15 rule while still providing good service to your current customer?", "scenario": "You''re helping another customer when you notice a new customer has entered and is browsing near the entrance, about 15 feet away from you."}, {"guidance": "Yes, still follow the rule but adapt the approach. Make eye contact if possible, smile, and offer a brief, respectful greeting like ''Hello, let me know if you need anything!'' Then give them space while staying observant and available. The key is acknowledging them without being intrusive while keeping the door open for assistance.", "question": "Should you still follow the Stop and Drop in 15 rule? How would you adapt your approach for this customer?", "scenario": "A customer walks in and immediately starts browsing intensively, seeming focused and potentially in a hurry. They don''t make eye contact when they enter."}], "objectives": ["Understand the critical importance of the first 20 seconds of customer interaction", "Master the three steps of the Stop and Drop in 15 rule", "Demonstrate proper timing, eye contact, and approach techniques", "Apply greeting skills consistently to create welcoming experiences for every customer"], "description": "Learn the essential skill of greeting customers effectively using our proven Stop and Drop in 15 approach to create positive first impressions that set the foundation for exceptional service.", "markdownContent": "# Creating Memorable First Impressions: The Stop and Drop in 15 Rule\n\n## Welcome to Your Customer Greeting Training\n\nAt Our Store, we believe that every customer deserves to feel welcomed and valued from the moment they step through our doors. This training will equip you with the skills to create those magical first moments that turn browsers into buyers and one-time visitors into loyal customers.\n\n## Why First Impressions Matter\n\n*\"You never get a second chance to make a first impression.\"*\n\nThis timeless wisdom is especially true in retail. Research shows that customers form their impression of our store in as little as **20 seconds**. Think about that – in less time than it takes to fold a sweater, a customer has already decided whether they feel comfortable, welcomed, and valued in our space.\n\nEvery day, we work hard to entice customers to visit our boutique. Don''t let that effort go to waste by missing the opportunity to greet them properly – or worse, by ignoring them entirely.\n\n## The Stop and Drop in 15 Rule\n\nAt Our Store, we use a simple but powerful approach called the **\"Stop and Drop in 15\" Rule**. Just like the childhood fire safety rule \"Stop, Drop, and Roll,\" our version is \"Stop and Drop in 15!\"\n\nThis rule ensures that every customer receives acknowledgment and feels welcomed within those critical first moments.\n\n### Step One: Take Action Within 15 Feet or 15 Seconds\n\n**The Trigger:** Whenever you see a customer:\n- Enter the store\n- Enter your section\n- Come within 15 feet of you while browsing\n\n**Your Response:** Complete steps two and three within **15 seconds** of noticing the customer.\n\n### Step Two: Break the Ice with STOP\n\n**STOP** what you are doing and:\n- Make genuine **eye contact**\n- Give them a **warm, welcoming smile**\n- Show that you''ve noticed and acknowledged their presence\n\nThese simple acts immediately put customers at ease and make them more receptive to your approach. Remember, this isn''t just about being polite – it''s about creating an emotional connection from the very first moment.\n\n### Step Three: Engage with DROP\n\n**DROP** whatever task you''re working on and:\n- Take a few steps in the customer''s direction\n- Offer a friendly **\"Hello!\"** or **\"Hi there!\"**\n- Maintain open, welcoming body language\n- Give a casual, friendly wave if appropriate\n\nBy moving toward the customer, you demonstrate that they are your priority and that you''re available to help.\n\n## The Psychology Behind the Approach\n\nThe Stop and Drop in 15 rule works because it:\n- **Acknowledges presence** – Customers feel seen and valued\n- **Reduces anxiety** – A friendly greeting puts nervous shoppers at ease\n- **Opens communication** – Creates a foundation for helpful service\n- **Demonstrates professionalism** – Shows we''re attentive and care about their experience\n\n## Tips for Success\n\n### Your Smile\n- Make it genuine and warm\n- Let it reach your eyes\n- Remember that smiles are contagious\n\n### Your Body Language\n- Keep posture open and welcoming\n- Avoid crossed arms or turning away\n- Move with purpose but not urgency\n\n### Your Voice\n- Use a warm, friendly tone\n- Match the energy of the store environment\n- Be genuine and authentic\n\n## Remember: Every Customer, Every Time\n\nConsistency is key to building Our Store''s reputation for exceptional service. Whether it''s your first customer of the day or your fiftieth, whether you''re having a great day or a challenging one, every customer deserves the same warm, professional greeting.\n\nBy mastering the Stop and Drop in 15 rule, you''re not just following a procedure – you''re creating the foundation for meaningful customer relationships and contributing to Our Store''s success.\n\n## Your Next Steps\n\nPractice the Stop and Drop in 15 rule until it becomes second nature. Pay attention to how customers respond to your greetings and notice the positive difference it makes in their shopping experience. Remember, you have the power to make someone''s day better with just a smile and a friendly hello.\n\nWelcome to the Our Store team – we''re excited to see you create wonderful first impressions for our valued customers!", "estimatedMinutes": 25}', '["43363e98-6ab7-47ad-b1b6-b4b147ccd668"]', 'in_review', NULL, '46870047', '2026-04-14 19:02:41.498265', '2026-04-14 19:02:41.498265'),
	('732c89d9-4fe1-43bd-ad2d-8857bc39831b', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'The Power of Customer Service: Understanding the Impact', '{"role": "New Associate", "title": "The Power of Customer Service: Understanding the Impact", "exercises": [{"guidance": "Ideal response should include: immediate acknowledgment and apology, empathetic listening, quick action to resolve (offer exchange, refund, or expedited repair), and follow-up to ensure satisfaction. Remember that this customer could tell 8-16 people about this experience - make it a positive story!", "question": "Knowing that 68% of customers leave due to poor treatment and that quick resolution leads to 95% customer retention, how would you handle this situation?", "scenario": "A customer approaches you looking frustrated. She explains that she bought a dress last week for a special event, but when she got home, she noticed a small tear in the fabric. The event is tomorrow, and she''s clearly upset about the situation."}, {"guidance": "Ideal response includes: warm, non-pressuring approach, offering specific assistance, asking open-ended questions to understand her needs, and providing personalized recommendations. Proactive service prevents the customer from becoming part of the ''silent majority'' who leave without expressing their needs.", "question": "Considering that 96% of dissatisfied customers never complain and just leave, how would you proactively approach this situation?", "scenario": "During a busy Saturday afternoon, you notice a customer browsing for several minutes without finding what she needs. She hasn''t asked for help, but you can see she looks a bit lost and overwhelmed by the selection."}], "objectives": ["Understand the financial impact of customer service on business success", "Recognize the cost of losing customers versus retaining them", "Learn the importance of quick complaint resolution", "Identify the ripple effect of both positive and negative customer experiences"], "description": "Learn why exceptional customer service is crucial for Our Store''s success through compelling statistics and real-world impact data. This foundational module helps new associates understand how their daily interactions directly affect customer retention and business profitability.", "markdownContent": "# The Power of Customer Service: Understanding the Impact\n\nWelcome to Our Store! As a fashion boutique, we pride ourselves on creating memorable experiences for every customer who walks through our doors. Understanding the true impact of customer service will help you excel in your role and contribute to our store''s success.\n\n## Why Customer Service Matters\n\nAt Our Store, every interaction counts. Here''s what the data tells us about the power of exceptional service:\n\n### The Reality of Customer Defection\n- **68% of customers leave because they feel poorly treated** - not because of price or product issues\n- Only 14% leave due to product dissatisfaction\n- A mere 9% leave for competitive reasons\n- This means **attitude and treatment are the biggest factors** in whether customers stay or go\n\n### The Cost of Losing Customers\n- It costs **5-6 times more to acquire a new customer** than to retain an existing one\n- Customer loyalty can be worth **10 times as much as a single purchase**\n- For a medium-sized company, just a 1% improvement in customer service could generate **$16 million in extra profits** over 5 years\n- Reducing customer defections can boost profits by **25-85%**\n\n## The Silent Majority\n\nHere''s something that might surprise you:\n- **For every customer who complains, 26 others remain silent**\n- Only 4% of dissatisfied customers actually voice their concerns\n- The other 96% simply leave and rarely return (91% never come back)\n\nThis means that the complaints we do hear represent a much larger group of potentially dissatisfied customers.\n\n## The Ripple Effect of Service\n\n### When Things Go Wrong\n- The average wronged customer tells **8-16 people** about their negative experience\n- Over 20% will tell **more than 20 people**\n- 13% of dissatisfied customers share their experience with **20 or more people**\n- It takes **12 positive service incidents** to make up for just 1 negative incident\n\n### When We Get It Right\n- Happy customers who have problems resolved tell **4-6 people** about their positive experience\n- **70% of complaining customers** will return if we resolve their issue favorably\n- **95% will return** if we resolve their complaint instantly\n- Quick, satisfactory resolution can lead to **96% customer retention** and referrals\n\n## The Power of Communication\n\n**80% of complaints have poor communication as their root cause.** This highlights the importance of:\n- Clear, friendly communication with customers\n- Active listening to understand their needs\n- Effective internal communication within our team\n\n## The Simple Solutions\n\nOften, it''s the small gestures that make the biggest difference:\n- **35% of customers** said a simple apology would have prevented them from going to a competitor\n- In 73% of cases where customers left, **no attempt was made to persuade them to stay**\n- Sometimes, acknowledging the issue and showing you care is enough\n\n## Your Role at Our Store\n\nAs a member of Our Store team, you have the power to:\n- Create positive experiences that customers will share with others\n- Turn potentially negative situations into opportunities to demonstrate our exceptional service\n- Build customer loyalty that extends far beyond a single purchase\n- Contribute directly to our store''s profitability and success\n\nRemember: every interaction is an opportunity to show why Our Store is special. Your warm, professional approach doesn''t just serve our customers—it serves our entire business community.", "estimatedMinutes": 25}', '["78060112-8264-4c56-b135-aa3b7544e829"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:09.987543', '2026-04-14 19:03:09.987543'),
	('4f780d47-6439-4f31-9e12-8d7c07e92f3f', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'knowledge_base', 'Customer Retention Statistics and Cost Impact', '{"tags": ["customer retention", "business costs", "profitability", "customer acquisition"], "title": "Customer Retention Statistics and Cost Impact", "summary": "Key statistics showing the financial impact of customer retention versus acquisition, demonstrating why keeping existing customers is more profitable than finding new ones.", "audience": "Management and sales staff", "category": "Business Intelligence", "paragraphs": [{"body": "It costs 5-6 times more to acquire a new customer than to retain an existing one. For medium-sized companies, just a 1% reduction in customer service problems could generate an extra $16 million in profits over 5 years. Customer loyalty is worth up to 10 times the value of a single purchase.", "heading": "Cost of Customer Acquisition vs Retention"}, {"body": "68% of customer defection occurs because customers feel poorly treated by staff - this is the leading cause of customer loss. Only 14% leave due to product dissatisfaction, 9% for competitive reasons, 3% move away, and 1% die. Reducing customer defections can boost profits by 25-85%.", "heading": "Why Customers Leave"}, {"body": "Only 4% of dissatisfied customers actually complain - 96% simply leave without saying anything. For every customer who complains, 26 others remain silent. Of those who don''t complain, 91% will never return to do business again.", "heading": "Silent Dissatisfaction"}]}', '["78060112-8264-4c56-b135-aa3b7544e829"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:22.726727', '2026-04-14 19:03:22.726727'),
	('dff436db-cd86-41d2-90e2-77d04a660e8b', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'knowledge_base', 'Complaint Resolution and Recovery Statistics', '{"tags": ["complaint resolution", "customer recovery", "word-of-mouth", "communication"], "title": "Complaint Resolution and Recovery Statistics", "summary": "Critical data on how effective complaint resolution can recover customer relationships and the consequences of poor service recovery.", "audience": "Customer service representatives and supervisors", "category": "Customer Service", "paragraphs": [{"body": "95% of complaining customers will return if you resolve their complaint instantly. If resolved favorably but not immediately, 70% will still return. However, it takes 12 positive service incidents to make up for one negative experience.", "heading": "The Power of Quick Resolution"}, {"body": "80% of complaints stem from poor communication, either with customers or within the organization. In 73% of cases where customers left, no attempt was made to retain them, even though 35% said a simple apology would have prevented their departure.", "heading": "Communication as Root Cause"}, {"body": "Dissatisfied customers tell 9-16 people about their negative experience, with 13-20% telling more than 20 people. In contrast, customers with resolved problems tell 4-6 people about their positive experience. This highlights the disproportionate impact of negative versus positive word-of-mouth.", "heading": "Word-of-Mouth Impact"}]}', '["78060112-8264-4c56-b135-aa3b7544e829"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:22.732349', '2026-04-14 19:03:22.732349'),
	('2c987af7-7d6e-4c4f-9adb-2785a749e527', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Add-On Selling Using Picture-Perfect Techniques', '{"role": "New Associate", "tags": ["sales", "add-on", "customer service", "storytelling"], "steps": [{"type": "action", "order": 1, "title": "Complete the primary sale", "description": "Ensure the customer has selected their main item and is ready to proceed. Confirm their satisfaction with the primary purchase before moving to add-ons.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Choose your add-on approach", "description": "Select one of three approaches: 1) Show them something that makes the first purchase better (enhancement approach), 2) Help them avoid future inconvenience (prevention approach), or 3) Generic approach (last resort only).", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Select enhancement or prevention approach", "description": "Choose your approach based on the customer''s situation and needs", "decisionOptions": [{"action": "Use the ''frosting on the cake'' enhancement approach", "condition": "If customer is building an outfit or accessorizing"}, {"action": "Use the ''avoid the return trip'' prevention approach", "condition": "If customer is preparing for travel or major wardrobe update"}]}, {"type": "action", "order": 4, "title": "Paint a vivid picture with specific details", "description": "Create a detailed, sensory description of how the add-on item will look, feel, or benefit them. Example: ''We just received a new shipment of Lenna Agnes pieces. I could pair a unique necklace with this outfit to make your friends jealous and ensure you have a one-of-a-kind look.''", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Wait for customer response and proceed accordingly", "description": "Give the customer time to visualize what you''ve described, then respond based on their interest level.", "decisionOptions": null}], "title": "Add-On Selling Using Picture-Perfect Techniques", "summary": "Learn how to increase sales by painting vivid pictures for customers rather than using generic phrases, using proven storytelling techniques to showcase additional products."}', '["ed62027e-fc04-457e-a790-28a78b64d378"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:51.829815', '2026-04-14 19:03:51.829815'),
	('e5e06d81-3266-460e-ba5e-6ad802755cff', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'The Cake Analogy Enhancement Technique', '{"role": "Lead", "tags": ["sales technique", "enhancement selling", "analogies", "accessories"], "steps": [{"type": "action", "order": 1, "title": "Set up the cake analogy", "description": "Ask the customer: ''Have you ever seen someone make a chocolate cake?'' Wait for their response to ensure engagement.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Complete the analogy setup", "description": "Continue with: ''It''s pretty good all on its own. What I''m going to show you is the frosting on the cake.'' This sets expectation that what follows will enhance their purchase.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Present the enhancement item with vivid details", "description": "Show specific accessories or complementary pieces that will complete their look. Use descriptive language that helps them visualize the final result, focusing on how it elevates their original purchase.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Assess customer interest", "description": "Observe customer reaction and body language to determine next steps", "decisionOptions": [{"action": "Proceed with styling and fitting", "condition": "If customer shows interest (touching item, asking questions)"}, {"action": "Offer to hold the item while they think or suggest a smaller enhancement", "condition": "If customer seems hesitant"}, {"action": "Gracefully transition to checkout while keeping door open for future visits", "condition": "If customer declines"}]}], "title": "The Cake Analogy Enhancement Technique", "summary": "Master the ''frosting on the cake'' approach to show customers how additional items can perfect their purchase and elevate their overall look."}', '["ed62027e-fc04-457e-a790-28a78b64d378"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:51.920791', '2026-04-14 19:03:51.920791'),
	('f1cdb1c6-d2d4-4231-99f9-edda7401287c', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Prevention-Based Add-On Selling Strategy', '{"role": "Manager", "tags": ["sales strategy", "prevention selling", "customer convenience", "wardrobe planning"], "steps": [{"type": "action", "order": 1, "title": "Identify prevention opportunities", "description": "Look for customers who are shopping for special events, travel, wardrobe refresh, or seasonal transitions. These situations often require multiple coordinated pieces.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Use the return trip analogy", "description": "Ask: ''Have you ever gotten home, ready to get dressed and found you didn''t have everything you needed so you had to go back to the store?'' Wait for their response to build connection.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Present the solution with specific items", "description": "Say: ''We''ve got everything you need right over here to save you a trip.'' Then show specific items that complete their wardrobe needs, explaining how each piece solves a potential gap.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Tailor approach based on customer type", "description": "Adjust your prevention strategy based on the customer''s specific situation", "decisionOptions": [{"action": "Focus on versatile pieces that mix and match", "condition": "If customer is traveling"}, {"action": "Emphasize complete look including undergarments and accessories", "condition": "If customer has special event"}, {"action": "Suggest foundational pieces that work with multiple outfits", "condition": "If customer is wardrobe building"}]}, {"type": "action", "order": 5, "title": "Train team on avoiding ''tent folding''", "description": "Coach associates to never use generic phrases like ''anything else?'' Instead, ensure they always paint specific pictures and create visual scenarios for customers.", "decisionOptions": null}], "title": "Prevention-Based Add-On Selling Strategy", "summary": "Implement the ''avoid the return trip'' technique to help customers anticipate their needs and prevent future inconvenience while increasing sales."}', '["ed62027e-fc04-457e-a790-28a78b64d378"]', 'in_review', NULL, '46870047', '2026-04-14 19:03:51.928427', '2026-04-14 19:03:51.928427'),
	('8e460159-c651-45fc-9195-94783280be16', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Mastering Add-On Sales Through Visual Storytelling', '{"role": "New Associate", "title": "Mastering Add-On Sales Through Visual Storytelling", "exercises": [{"guidance": "Start with the cake script, then paint a specific picture. Example: ''Have you ever seen someone make a chocolate cake? It''s pretty good on its own. What I''m going to show you is the frosting on the cake. I''m picturing you in this dress with our new gold statement earrings and this delicate bracelet - you''ll have that perfect balance of elegance and glamour that will make your date absolutely speechless.''", "question": "Using the cake analogy approach, how would you suggest additional items to complete her look?", "scenario": "A customer has just selected a beautiful black dress for a dinner date. She seems excited about her choice but hasn''t mentioned accessories."}, {"guidance": "Connect to her concern about first impressions. Example: ''Have you ever gotten ready for an important day and realized you didn''t have quite the right accessories to pull your look together? Let me show you a few pieces that will give you several different sophisticated looks with this blazer, so you''ll feel confident and polished every day of your first week.''", "question": "How would you use the ''preventing future problems'' approach to suggest additional items?", "scenario": "A customer is buying a blazer for a new job that starts next week. She mentions she''s nervous about making a good first impression."}, {"guidance": "Stop and create a visual. Example: ''Actually, let me show you something that would make this outfit perfect for brunch with friends - this lightweight scarf would add just the right pop of color and give you that effortlessly chic look that everyone will want to copy.''", "question": "How would you quickly pivot to paint a picture instead?", "scenario": "You notice yourself about to say ''Anything else?'' to a customer who just bought a casual weekend outfit."}], "objectives": ["Understand the three approaches to add-on selling and when to use each", "Create vivid mental pictures using the cake analogy and descriptive language", "Replace generic phrases with compelling, visual sales suggestions", "Develop personalized add-on scripts for fashion and accessories"], "description": "Learn how to increase sales by painting vivid pictures for customers instead of using generic phrases. Master three proven approaches to add-on selling that create compelling customer experiences.", "markdownContent": "# Mastering Add-On Sales Through Visual Storytelling\n\n## Welcome to Our Store''s Add-On Sales Training\n\nAt Our Store, we believe every customer deserves a complete, beautiful look. This training will help you become confident in suggesting additional pieces that truly enhance your customer''s style while increasing our store''s success.\n\n## The Power of Add-On Sales\n\nOnce a customer has selected their main item, you have **three strategic approaches**:\n\n1. **Make them see something that makes the first purchase better**\n2. **Help them avoid future inconvenience**\n3. **Fold your tent** (the least effective option)\n\n## Approach 1: The Cake Analogy - Making It Better\n\nThis is perfect for our fashion boutique environment where accessories and complementary pieces can transform an outfit.\n\n### The Script:\n*\"Have you ever seen someone make a chocolate cake?\"* (wait for their response)\n\n*\"It''s pretty good all on its own. What I''m going to show you is the frosting on the cake.\"*\n\n**Why this works:**\n- Sets a positive expectation\n- Feels natural and easy\n- Creates anticipation for something special\n\n### Fashion Example:\n*\"We just received a new shipment of Lenna Agnes pieces. I could pair a unique necklace with this outfit to make your friends jealous and ensure you have a one-of-a-kind look.\"*\n\n## Approach 2: Preventing Future Problems\n\nIdeal for customers preparing for special events, trips, or wardrobe updates.\n\n### The Script:\n*\"Have you ever gotten home, ready to get dressed and found you didn''t have everything you needed so you had to go back to the store?\"* (wait for response)\n\n*\"We''ve got everything you need right over here to save you a trip.\"*\n\n## What NOT to Do: Folding Your Tent\n\nThe phrase **\"Anything else?\"** is the most common mistake in retail.\n\n**Why it fails:**\n- Creates no mental picture\n- Shows no enthusiasm\n- Wastes the opportunity after all your hard work\n\n## The Restaurant Lesson\n\nCompare these server approaches:\n\n❌ **\"Anything else?\"** → You see nothing\n\n❌ **\"Do you want some pie or cookies or ice cream?\"** → Still nothing\n\n✅ **\"We have fresh-made apple pie just out of the oven. I could drizzle warm caramel on it and top it off with vanilla bean ice cream.\"** → You can practically taste it!\n\n## Creating Your Own Picture-Painting Scripts\n\n### Key Elements:\n1. **Be specific** - mention exact items, colors, or styles\n2. **Use sensory language** - help them imagine how it looks, feels\n3. **Connect to emotions** - confidence, uniqueness, admiration\n4. **Show the complete vision** - how pieces work together\n\n### Practice Phrases for Our Store:\n- *\"This would look stunning with...\"*\n- *\"I''m picturing you in this with...\"*\n- *\"To complete this look, imagine adding...\"*\n- *\"This piece would make your outfit absolutely unforgettable with...\"*\n\n## Your Success Starts Now\n\nRemember, you''ve already done the hard work of helping them find something they love. Don''t fold your tent at the finish line. Paint a picture that helps them see their complete, perfect look.\n\nEvery suggestion should make them **see** themselves looking and feeling amazing.", "estimatedMinutes": 25}', '["ed62027e-fc04-457e-a790-28a78b64d378"]', 'in_review', NULL, '46870047', '2026-04-14 19:04:22.613479', '2026-04-14 19:04:22.613479'),
	('4bab1259-5ac1-401a-aec6-39312566976b', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Communication and Language Best Practices', '{"role": "New Associate", "tags": ["customer service", "communication", "sales floor", "language"], "steps": [{"type": "action", "order": 1, "title": "Listen actively to customer inquiries", "description": "Give customers your full attention and let them express their needs or concerns completely before responding.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Use positive language alternatives", "description": "Replace negative phrases with solution-focused alternatives: Say ''That''s a great question, let me find out for you'' instead of ''I don''t know.'' Use ''I''d be happy to help you'' instead of ''I''m busy right now.''", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Assess the situation type", "description": "Determine if the customer needs product information, has a concern, or requires assistance with store policies.", "decisionOptions": [{"action": "Research the answer or find someone who can help", "condition": "If customer needs product information"}, {"action": "Apologize and focus on solutions", "condition": "If customer has a concern or complaint"}, {"action": "Explain policy flexibility and offer alternatives", "condition": "If policy question arises"}]}, {"type": "action", "order": 4, "title": "Follow up with additional assistance", "description": "Instead of asking ''Will that be all?'', use phrases like ''Let me show you...'' or ''Have you tried...?'' to continue providing value and potentially increase sales.", "decisionOptions": null}], "title": "Customer Communication and Language Best Practices", "summary": "A comprehensive guide for using positive, solution-focused language when interacting with customers on the sales floor."}', '["019d0c42-e8e3-4486-b69d-a9398fee79b2"]', 'in_review', NULL, '46870047', '2026-04-14 19:04:49.375682', '2026-04-14 19:04:49.375682'),
	('4c860836-0de8-4558-ae1a-fa63acd7f2cc', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Handling Customer Concerns and Policy Exceptions', '{"role": "Lead", "tags": ["policy management", "customer retention", "problem resolution", "escalation"], "steps": [{"type": "action", "order": 1, "title": "Acknowledge the customer''s concern", "description": "Listen without interrupting and acknowledge their situation with phrases like ''I understand your concern'' rather than dismissive language.", "decisionOptions": null}, {"type": "decision", "order": 2, "title": "Evaluate policy flexibility options", "description": "Consider the customer''s history, the nature of their request, and the potential long-term value of the customer relationship.", "decisionOptions": [{"action": "Explain policy with empathy and offer alternatives", "condition": "If standard policy can be applied with customer satisfaction"}, {"action": "Proceed to make reasonable accommodation", "condition": "If policy exception may be warranted"}, {"action": "Escalate to manager with recommendation", "condition": "If situation requires manager approval"}]}, {"type": "action", "order": 3, "title": "Communicate policy with flexibility", "description": "Use language like ''Typically our policy is ____, but I want to make this right for you. This is what I can do...'' instead of rigid policy statements.", "decisionOptions": null}, {"type": "action", "order": 4, "title": "Implement solution and confirm satisfaction", "description": "Execute the agreed-upon solution and ask the customer if the resolution meets their needs before concluding the interaction.", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Document exception if applicable", "description": "Record any policy exceptions made and the reasoning for future reference and team learning.", "decisionOptions": null}], "title": "Handling Customer Concerns and Policy Exceptions", "summary": "Step-by-step process for addressing customer concerns while maintaining flexibility with store policies to ensure customer satisfaction."}', '["019d0c42-e8e3-4486-b69d-a9398fee79b2"]', 'in_review', NULL, '46870047', '2026-04-14 19:04:49.387425', '2026-04-14 19:04:49.387425'),
	('e504143e-24b9-47c3-bc1b-0e824ea8ae44', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Product Availability and Alternative Solutions', '{"role": "Manager", "tags": ["inventory management", "alternative selling", "customer retention", "sales conversion"], "steps": [{"type": "action", "order": 1, "title": "Confirm product availability", "description": "Check inventory system thoroughly, including backstock, other sizes, and alternative locations before confirming unavailability.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Present the situation positively", "description": "Say ''That item is currently out of stock, but we have a great alternative'' instead of simply stating ''We''re out of that item.''", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Determine customer preference for resolution", "description": "Ask if they''d like to see alternatives now or be contacted when the item returns to stock.", "decisionOptions": [{"action": "Show similar products that meet their needs", "condition": "If customer wants to see alternatives"}, {"action": "Take contact information for restock notification", "condition": "If customer prefers to wait"}, {"action": "Show alternatives first, then offer restock notification option", "condition": "If customer is unsure"}]}, {"type": "action", "order": 4, "title": "Provide comprehensive alternatives", "description": "Show similar items, explain benefits, and check other store locations if applicable. Use phrases like ''Let me see if another location might have this in your size.''", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Set up follow-up system", "description": "If customer chooses to wait, enter their information in the restock notification system and provide expected timeframe for callback.", "decisionOptions": null}], "title": "Product Availability and Alternative Solutions", "summary": "Protocol for handling out-of-stock situations and converting potential lost sales into customer satisfaction and future opportunities."}', '["019d0c42-e8e3-4486-b69d-a9398fee79b2"]', 'in_review', NULL, '46870047', '2026-04-14 19:04:49.396478', '2026-04-14 19:04:49.396478'),
	('946832a0-0159-473b-a1b9-1ac6831e2328', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Elevating Your Sales Floor Language', '{"role": "New Associate", "title": "Elevating Your Sales Floor Language", "exercises": [{"guidance": "Use: ''Typically our policy is that sale items are final sale, but I want to make sure you''re completely satisfied. Let me know if you''re not happy with it and we''ll make it right.'' This acknowledges the policy while showing flexibility and care for their satisfaction.", "question": "How would you explain this policy while maintaining flexibility and customer focus?", "scenario": "A customer asks about the return policy for a sale dress they''re considering. You know sale items typically can''t be returned."}, {"guidance": "Try: ''That jacket is currently out of stock in medium, but we have a similar style that''s really popular, or I can take your information and call you the moment we get more mediums in. Which would you prefer?'' This offers alternatives and shows you want to help them find what they need.", "question": "What would you say to turn this into a positive interaction?", "scenario": "A customer is looking for a specific jacket in size medium that you know is out of stock. They seem disappointed."}, {"guidance": "Say: ''I''d be happy to help you with that!'' Then put down what you''re doing and give them your full attention. Never say you''re busy—customers are always our priority.", "question": "How do you respond to show you''re happy to help?", "scenario": "A customer approaches you while you''re folding clothes and asks about sizes available for a particular top."}, {"guidance": "Respond with: ''That''s a great question about the pricing. Let me find out exactly what we can do for you.'' Then get a manager or check the system. This shows you''re taking their concern seriously and will find an answer.", "question": "How do you handle this without saying ''I don''t know'' or ''I''m new here''?", "scenario": "A customer is frustrated because they believe an item was marked at a different price. You''re not sure about pricing policies."}], "objectives": ["Identify 12 common problematic phrases that can damage customer relationships", "Master positive alternatives that demonstrate helpfulness and solution-focused thinking", "Apply customer-centric language techniques to real sales floor scenarios", "Build confidence in handling challenging customer interactions with professional warmth"], "description": "Learn to transform common problematic phrases into customer-friendly language that builds rapport, demonstrates flexibility, and creates positive shopping experiences that keep customers coming back to Our Store.", "markdownContent": "# Elevating Your Sales Floor Language\n\nWelcome to Our Store! At our fashion boutique, every customer interaction is an opportunity to create a memorable experience that reflects our professional and warm brand values. The words we choose can make the difference between a one-time shopper and a loyal customer who becomes part of our Our Store family.\n\n## Why Your Words Matter\n\nIn retail, you are only as successful as your last customer interaction. Sometimes we might use phrases that unintentionally put customers off, even when we mean well. Today, we''ll explore how to transform potentially problematic language into positive, solution-focused communication.\n\n## The Power of Positive Alternatives\n\n### 1. From Uncertainty to Action\n**Instead of:** \"I don''t know\"\n**Say:** \"That''s a great question. Let me find out for you.\"\n\nCustomers don''t expect you to know everything about every piece in our boutique, but they do expect you to care enough to find answers.\n\n### 2. From Rigid Rules to Flexible Solutions\n**Instead of:** \"All sales are final\"\n**Say:** \"Let us know if you''re not satisfied and we''ll make it right.\"\n\nWhile we have policies for good reasons, our priority is keeping customers happy and maintaining Our Store''s reputation for exceptional service.\n\n### 3. From Dismissive to Understanding\n**Instead of:** \"Calm down\"\n**Say:** \"I apologize for [specific issue], but would you be willing to try [solution]?\"\n\nWhen customers are frustrated, they need to feel heard before they can hear solutions.\n\n### 4. From Rejection to Welcome\n**Instead of:** \"We''re closed\"\n**Say:** \"We close at [time] and reopen at [time]. Is there something I can quickly help you with now?\"\n\nCustomers who come to Our Store want to shop with us. Let''s find ways to accommodate when possible.\n\n### 5. From Ending to Extending\n**Instead of:** \"Will that be all?\"\n**Say:** \"Let me show you...\" or \"Have you tried...?\"\n\nThis keeps the conversation and selling opportunity alive while showing genuine interest in their complete look.\n\n### 6. From Limitations to Possibilities\n**Instead of:** \"I can''t do that\"\n**Say:** \"Let me get a manager to take a look at that.\"\n\nThere''s always someone who might have different options or authority to help.\n\n### 7. From Unavailable to Alternative\n**Instead of:** \"We''re out of that item\"\n**Say:** \"That item is currently out of stock, but we have a great alternative,\" or \"I can give you a ring when it''s back in stock. Is that okay?\"\n\nOut of stock doesn''t mean out of options.\n\n### 8. From Policy to Partnership\n**Instead of:** \"That''s against our policy\"\n**Say:** \"Typically our policy is [policy], but I want to make this right for you. This is what I can do...\"\n\nPolicies guide us, but customer satisfaction drives our success.\n\n### 9. From Inexperience to Dedication\n**Instead of:** \"I''m new here\"\n**Say:** \"Please bear with me and I''ll get you the help you need.\"\n\nCustomers care more about your willingness to help than your tenure.\n\n### 10. From Abrupt to Respectful\n**Instead of:** \"Hold on\"\n**Say:** \"Are you able to hold for a moment?\" or \"It''s going to be a few moments, do you mind waiting?\"\n\nAsking permission shows respect for their time.\n\n### 11. From Dismissive to Welcoming\n**Instead of:** \"I''m busy right now\"\n**Say:** \"I''d be happy to help you.\"\n\nCustomers are never an interruption—they''re the reason we''re here.\n\n### 12. From Confrontational to Collaborative\n**Instead of:** \"You''re wrong\"\n**Say:** \"I think there has been a misunderstanding, but this is what we can do to make it right for you.\"\n\nFocus on solutions, not fault.\n\n### 13. From Dismissive to Helpful\n**Instead of:** \"If you didn''t see it, then we must not have it\"\n**Say:** \"Let''s see if we can find one for you,\" or \"Let me see if another location might have this in your size/color.\"\n\nWhen customers ask for help finding something, they''re telling us they''re ready to buy.\n\n## Making It Natural\n\nThese alternatives might feel formal at first, but with practice, they''ll become second nature. The key is maintaining Our Store''s warm, professional tone while always looking for ways to help rather than reasons why we can''t.\n\n## Your Communication Toolkit\n\nRemember these principles:\n- **Lead with empathy**: Acknowledge their needs and feelings\n- **Focus on solutions**: What CAN we do?\n- **Show flexibility**: Policies guide us, but customer satisfaction is our goal\n- **Ask permission**: Respect their time and preferences\n- **Stay positive**: Frame everything in terms of possibilities\n\n## Practice Makes Perfect\n\nThe more you use these positive alternatives, the more natural they''ll become. Soon, you''ll find yourself automatically choosing words that make customers feel valued and understood—exactly what we want every Our Store experience to be.", "estimatedMinutes": 25}', '["019d0c42-e8e3-4486-b69d-a9398fee79b2"]', 'in_review', NULL, '46870047', '2026-04-14 19:05:26.421232', '2026-04-14 19:05:26.421232'),
	('d74d886d-a4ff-46ac-ae2b-669908fb7cef', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Customer Greeting and Initial Engagement', '{"role": "New Associate", "tags": ["greeting", "customer service", "first impression", "rapport"], "steps": [{"type": "action", "order": 1, "title": "Apply the 15-Second Rule", "description": "Within 15 seconds of a customer entering the store or coming within 15 feet of you, STOP what you are doing and make eye contact with a genuine smile.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "DROP and Approach", "description": "DROP your current task, take a few steps toward the customer, and offer a friendly ''Hello!'' with open body posture (body erect, hands away from body).", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Initiate Conversation", "description": "Use one of the approved greeting options such as ''What brings you in today?'' or ''Tell me what you are shopping for?'' to begin building rapport.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Customer Response Assessment", "description": "Evaluate the customer''s openness to assistance based on their verbal and non-verbal cues.", "decisionOptions": [{"action": "Continue with qualifying their needs and begin suggestive selling", "condition": "If customer is receptive and engages"}, {"action": "Respectfully step back but remain available, saying ''My name is ___, let me know if I can help with anything''", "condition": "If customer prefers to browse alone"}]}, {"type": "action", "order": 5, "title": "Provide Business Card", "description": "Before the customer leaves, give them a business card with your name written on it for future reference and to encourage return visits.", "decisionOptions": null}], "title": "Customer Greeting and Initial Engagement", "summary": "A systematic approach to making positive first impressions and building rapport with customers using the ''Stop and Drop in 15'' rule."}', '["43ab573c-ea3b-4aed-8499-7b1e2e0e7750"]', 'in_review', NULL, '46870047', '2026-04-14 19:05:58.694995', '2026-04-14 19:05:58.694995'),
	('a7c3c1fe-80ed-4e16-8ad8-5f7222ce7b14', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Dressing Room Sales Maximization', '{"role": "Lead", "tags": ["dressing room", "sales maximization", "add-ons", "customer service"], "steps": [{"type": "action", "order": 1, "title": "Stay Available and Monitor", "description": "Remain near the dressing room area and be available for customer needs. Watch for customers coming out to view items in the larger mirror.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Check In Using Customer Name", "description": "After giving the customer a few minutes, check on them by calling them by name and asking if they need different sizes or assistance.", "decisionOptions": null}, {"type": "decision", "order": 3, "title": "Decision: Customer Satisfaction Assessment", "description": "Evaluate whether the customer seems satisfied with their current selections.", "decisionOptions": [{"action": "Find 2-3 additional options and place them on their door, announcing you found more choices", "condition": "If customer seems unsatisfied or undecided"}, {"action": "Proceed to suggest complementary items", "condition": "If customer seems satisfied with selections"}]}, {"type": "action", "order": 4, "title": "Suggest Complementary Items", "description": "Once customer has found items they like, suggest accessories, shoes, or other pieces that complete their look based on what they''re purchasing.", "decisionOptions": null}, {"type": "action", "order": 5, "title": "Provide Honest Expert Opinion", "description": "When customers ask for your opinion or come out to show you items, give honest, confident feedback as the fashion expert to help them make the best decision.", "decisionOptions": null}, {"type": "action", "order": 6, "title": "Manage Unwanted Items", "description": "Offer to clear out any items the customer doesn''t want to avoid clutter and confusion in the fitting room.", "decisionOptions": null}], "title": "Dressing Room Sales Maximization", "summary": "A comprehensive process for maximizing sales opportunities while customers are trying on merchandise in the fitting room."}', '["43ab573c-ea3b-4aed-8499-7b1e2e0e7750"]', 'in_review', NULL, '46870047', '2026-04-14 19:05:58.715145', '2026-04-14 19:05:58.715145'),
	('de88dde2-b743-4cb4-8cd0-8c172d3143e8', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'sop', 'Complete Customer Experience and Follow-Up', '{"role": "Manager", "tags": ["customer experience", "follow-up", "retention", "referrals"], "steps": [{"type": "action", "order": 1, "title": "Execute Complete Sales Process", "description": "Ensure team completes all steps: greet and start conversation, start dressing room, suggest add-ons, follow up in dressing room, and check out thanking by name.", "decisionOptions": null}, {"type": "action", "order": 2, "title": "Checkout Process", "description": "Don''t rush customer to register after dressing room. Offer to hold their selections behind counter while they continue browsing, then suggest jewelry or accessories at checkout.", "decisionOptions": null}, {"type": "action", "order": 3, "title": "Create Customer Profile", "description": "Fill out a personal customer sheet documenting their size, style preferences, and personal details for future visits.", "decisionOptions": null}, {"type": "decision", "order": 4, "title": "Decision: Follow-Up Method Selection", "description": "Choose appropriate follow-up method based on the connection level and customer preference.", "decisionOptions": [{"action": "Call within a few days to see how their outfit worked out for them", "condition": "If strong personal connection was made"}, {"action": "Send a handwritten thank you note mentioning specific conversation details", "condition": "If standard positive interaction occurred"}]}, {"type": "action", "order": 5, "title": "Ongoing Relationship Maintenance", "description": "Contact customers when new items arrive that match their style, and reach out if they haven''t visited in a while to encourage return visits.", "decisionOptions": null}, {"type": "action", "order": 6, "title": "Monitor Team Performance", "description": "Ensure all associates are providing consistent excellent service to every customer regardless of appearance, as negative experiences spread faster than positive ones.", "decisionOptions": null}], "title": "Complete Customer Experience and Follow-Up", "summary": "Ensuring every customer receives exceptional service from greeting to follow-up, building long-term relationships and encouraging referrals."}', '["43ab573c-ea3b-4aed-8499-7b1e2e0e7750"]', 'in_review', NULL, '46870047', '2026-04-14 19:05:58.730885', '2026-04-14 19:05:58.730885'),
	('f7d15fd3-0aab-4607-936c-b3dc8e26a4f2', 'b0396051-34a1-475b-addc-771e580a5224', '0b61a5ec-bd99-48c2-a366-5ea92195b977', 'training', 'Building Customer Connections: The Art of Authentic Selling', '{"role": "New Associate", "title": "Building Customer Connections: The Art of Authentic Selling", "exercises": [{"guidance": "Stop what you''re doing, make eye contact and smile, then approach within 15 seconds. A good opener might be ''Tell me what you''re shopping for?'' or ''What brings you in today?'' to understand her specific needs and reduce the overwhelming feeling.", "question": "How would you apply the ''Stop and Drop in 15'' rule and which conversation starter would you choose?", "scenario": "A customer enters the store and begins browsing the dress section. She appears to be looking for something specific but seems a bit overwhelmed by the options."}, {"guidance": "Be real by acknowledging her uncertainty, be the expert by asking about the specific concerns (fit, style, occasion), be directive by offering to see it on her or suggesting alternatives, and be thankful by using her name and showing you care about her finding the right piece.", "question": "How would you respond using the four pillars of authentic selling?", "scenario": "A customer is in the fitting room and calls out ''I''m not sure about this dress.'' She sounds uncertain and hasn''t come out to show you."}, {"guidance": "Use ''you'' to personalize (''Which one makes YOU feel more confident?''), be directive with a solid opinion based on fit and style, and use words like ''love'' (''I think you''ll love how this one flatters your figure'') to help them visualize the positive outcome.", "question": "Which motivational words would you use, and how would you help them decide?", "scenario": "A customer is deciding between two similar tops and says, ''I just can''t make up my mind. They''re both nice.''"}], "objectives": ["Apply the four pillars of authentic selling in every customer interaction", "Execute the ''Stop and Drop in 15'' rule to create positive first impressions", "Identify customer needs through effective questioning and active listening", "Use motivational language to guide customers toward confident purchasing decisions"], "description": "Master the foundational principles of authentic selling and customer engagement through genuine connection, expert guidance, and exceptional service.", "markdownContent": "# Building Customer Connections: The Art of Authentic Selling\n\n## Welcome to Our Store''s Sales Philosophy\n\nAt Our Store, we believe that exceptional sales performance stems from authentic human connections. When you genuinely care about helping customers look and feel their best, sales naturally follow.\n\n## The Four Pillars of Authentic Selling\n\nOur approach to selling is built on four fundamental principles:\n\n### 1. Be Real\n**Goal:** Create genuine likeability and trust\n\n- Get to know your customer as a person\n- Listen actively and respond to their reactions\n- Be honest and sincere in all interactions\n- Show genuine interest in their needs and preferences\n\n### 2. Be the Expert\n**Goal:** Establish credibility and confidence in your recommendations\n\n- Stay current with fashion trends and seasonal collections\n- Know our merchandise locations and brand offerings\n- Offer informed opinions while reading customer reactions\n- Share styling tips and product knowledge confidently\n\n### 3. Be Directive\n**Goal:** Guide customers to decisions that truly serve them\n\n- Accompany customers to fitting rooms when possible\n- Provide honest, constructive feedback on fit and style\n- Offer solid opinions, especially for indecisive customers\n- Suggest alternatives when we don''t have exact matches\n- Proactively check other store locations for desired items\n\n### 4. Be Thankful\n**Goal:** Ensure customers feel valued and want to return\n\n- Use customers'' names throughout their visit\n- Express gratitude during checkout and as they leave\n- Provide your business card with your name for future reference\n- Make every customer feel important and appreciated\n\n## Creating Powerful First Impressions\n\n### The ''Stop and Drop in 15'' Rule\n\nCustomers form impressions within 20 seconds of entering our store. Here''s how to make those seconds count:\n\n**When to Act:** Within 15 feet or 15 seconds of a customer entering your area\n\n**Step One - STOP:**\n- Stop what you''re doing immediately\n- Make genuine eye contact\n- Offer a warm, welcoming smile\n\n**Step Two - DROP:**\n- Drop your current task\n- Take steps toward the customer\n- Greet them with enthusiasm\n- Use open body language (hands away from body, upright posture)\n\n### Conversation Starters That Connect\n\n**Need-Based Openers:**\n- \"What brings you in today?\"\n- \"Tell me what you''re shopping for?\"\n- \"Are you looking for something specific I can help you find?\"\n\n**Compliment-Based Openers:**\n- \"I love your [item], where did you find it?\"\n- \"That color looks amazing on you!\"\n\n**Situational Openers:**\n- \"Are you having a fun shopping day together?\"\n- \"Let me know if you''d like me to grab different sizes for you.\"\n\n## Understanding Your Customer''s True Needs\n\n### Common Mistakes to Avoid\n- Failing to discover what customers actually want\n- Focusing on your sales goals instead of their needs\n- Talking more than listening\n- Confusing product features with customer benefits\n- Lacking knowledge about current promotions and pricing\n\n### The Three-Step Qualification Process\n\n**Step One: Discover the ''Why''**\n- Are they shopping for a specific event?\n- Are they browsing or seeking something particular?\n- What''s their timeline and budget consideration?\n\n**Step Two: Suggest Thoughtfully**\n- Base recommendations on your conversation insights\n- Make genuine conversation while showing merchandise\n- Surprise them with personalized attention\n\n**Step Three: Refine and Focus**\n- Work toward 2-3 strong options to try\n- Pay attention to verbal and non-verbal cues\n- Adjust suggestions based on their reactions\n\n## The Language of Motivation\n\nCertain words and phrases naturally encourage customers to move forward with purchases:\n\n- **\"You\"** - Makes the conversation personal and customer-focused\n- **\"Guarantee\"** - Provides security and confidence in their choice\n- **\"Discover\"** - Appeals to curiosity and the excitement of finding something special\n- **\"Love\"** - \"You''re going to love how this looks on you!\"\n- **\"Save\"** - Whether time, money, or effort, everyone wants to save something\n- **\"New\"** - Positions items as current and on-trend\n- **\"One-of-a-kind\"** - Perfect for unique pieces like our exclusive collections\n\n## Maximizing Fitting Room Success\n\n### The Three-Stage Approach\n\n**Stage One: Stay Available**\n- Remain nearby and accessible\n- Check in by name if they don''t emerge\n- Be ready with your honest opinion when they show you items\n\n**Stage Two: Strategic Additions**\n- If they seem unsatisfied, thoughtfully add 1-2 more options\n- Place items on their door with a brief explanation\n- Avoid overwhelming them with too many choices\n- Offer to remove items they''ve decided against\n\n**Stage Three: Complete the Look**\n- Once they''ve found core pieces, suggest complementary items\n- Pay attention to their style preferences from what they''ve chosen\n- Always be honest in your feedback - their trust is more valuable than any single sale\n\n**Remember:** Be an aggressive motivator, not an aggressive pusher. Read your customer and adapt accordingly.\n\n## Your Next Steps\n\nPractice makes perfect. Start with one pillar at a time, and soon these techniques will become natural parts of every customer interaction. Remember, when you genuinely focus on helping customers look and feel their best, exceptional sales results follow naturally.", "estimatedMinutes": 25}', '["43ab573c-ea3b-4aed-8499-7b1e2e0e7750"]', 'in_review', NULL, '46870047', '2026-04-14 19:06:38.443212', '2026-04-14 19:06:38.443212');


