INSERT INTO public.daily_quotes (id, store_id, quote_date, quote_text, quote_author, generated_by_ai, created_at) VALUES
	('679ad210-2074-458f-9f81-a9532187a0ec', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-24', 'Excellence is never an accident. It is always the result of high intention, sincere effort, and intelligent execution; it represents the wise choice of many alternatives.', 'Aristotle', true, '2026-02-24 20:36:08.203957+00'),
	('2f7192e0-fa47-451a-9a62-097ff8cb5fbc', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-25', 'Lean is spelled P-E-O-P-L-E. Grow your people first.', 'Paul Akers', false, '2026-02-25 05:02:32.124646+00'),
	('62fe3830-8271-4539-8e91-a17c40fcaadf', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-26', 'Strive for progress, not perfection.', 'Unknown', false, '2026-02-26 05:09:57.821991+00'),
	('a7294081-3999-4a76-ad05-ef534c5b9ffe', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-27', 'The impediment to action advances action. What stands in the way becomes the way.', 'Marcus Aurelius', false, '2026-02-27 05:12:14.1822+00'),
	('4d21af8a-acec-4de3-8b5e-9bd4504282bf', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-28', 'Excellence is not a destination; it is a continuous journey that never ends.', 'Brian Tracy', true, '2026-02-28 05:01:23.863781+00'),
	('27996736-e066-497c-be33-a7fd93382b04', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-02', 'One piece of flow is the ideal — finish what you start before starting something new.', 'Lean Principle', false, '2026-03-02 15:31:03.672713+00'),
	('9e022e9a-1757-42cb-a949-98806a8f864b', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-03', 'The customer''s experience is the sum of all the small details we choose to perfect or ignore.', 'Original Wisdom', true, '2026-03-03 19:53:50.247951+00'),
	('0c350164-279d-4cc3-b15b-ddd081ae01ea', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-04', 'The best way to learn is to do; the worst way to teach is to talk.', 'Paul Akers', true, '2026-03-04 15:37:31.838354+00'),
	('6dbe78a6-785b-4f2e-9d0a-78da97784dd9', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-06', 'The customer doesn''t care how much you know until they know how much you care. Excellence is not a destination—it''s a way of traveling through every interaction.', 'Original', true, '2026-03-06 15:33:37.253903+00'),
	('e5c5b26e-83b4-4602-ac43-9f9851fdca3f', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-07', 'The floor is your dojo, every customer interaction your practice. Master the fundamentals, then innovate from strength.', 'Original', true, '2026-03-07 08:16:24.675843+00'),
	('e048ece1-7220-4857-ba0f-763a4eae1c23', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-10', 'Small daily improvements are the key to staggering long-term results.', 'Robin Sharma', false, '2026-03-10 17:58:06.94828+00'),
	('6ab825c8-5f63-467a-a333-53e5c901183b', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-15', 'Every day you don''t improve, someone else is getting better. Excellence is not a destination—it''s a daily commitment to being slightly better than yesterday.', 'Original', true, '2026-03-15 21:55:12.589227+00'),
	('731b61c3-a414-436a-8f61-38ada946a299', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-17', 'Every small improvement you make today is a gift to the customer who walks through your doors tomorrow.', 'Original', true, '2026-03-17 17:36:57.393508+00'),
	('9ab5eeaa-6f27-4947-84b2-e36f9b691155', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-18', 'The most dangerous kind of waste is the waste we do not recognize.', 'Shigeo Shingo', true, '2026-03-18 16:55:06.120426+00'),
	('49871931-e464-4573-96ef-61e26e62b8a4', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-19', 'The customer''s experience is the sum of all the small details we get right. Excellence isn''t an act, but a habit we practice in every interaction.', 'Original Wisdom', true, '2026-03-19 14:27:26.597998+00'),
	('eed6301f-1085-4bc4-a156-b33256f6895d', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-20', 'The gemba is where the truth lives. Go see, ask why, show respect.', 'Taiichi Ohno', true, '2026-03-20 16:54:52.853464+00'),
	('925c3693-42b0-494d-a773-b801dde9b959', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-23', 'The customer''s experience is the sum of all the small details we perfect, not the big gestures we attempt.', 'Original', true, '2026-03-23 14:59:32.140249+00'),
	('34b5efde-0483-44b2-99bd-c2ae635a5627', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-24', 'Every small improvement you make today becomes the foundation for tomorrow''s excellence. The customer who walks into your store doesn''t see the effort—they feel the care.', 'Original', true, '2026-03-24 14:10:00.99977+00'),
	('fc95a47d-9c3e-4e15-b86a-c7c8c6d11793', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-25', 'The way to get started is to quit talking and begin doing.', 'Walt Disney', true, '2026-03-25 11:35:26.217909+00'),
	('193d89d2-8ece-4fd8-b7eb-cb9723fff661', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-01', 'The beautiful thing about learning is nobody can take it away from you.', 'B.B. King', true, '2026-04-01 16:35:04.126187+00'),
	('4c2fd2b1-9ddd-429f-a1d3-a18121700490', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-02', 'The customer sees the result, not the struggle. Make every small improvement count, because excellence is built one detail at a time.', 'Original', true, '2026-04-02 14:03:45.055971+00'),
	('2d70e6b0-48ce-4dad-b020-aa2d2bae8afd', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-03', 'The master has failed more times than the beginner has even tried. Every customer interaction, every display reset, every problem solved builds the expertise that transforms good into great.', 'Original', true, '2026-04-03 14:21:40.236085+00'),
	('beaa93dd-2681-4774-a3cf-4493f357dc05', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-04', 'Continuous improvement is better than delayed perfection.', 'Mark Twain', false, '2026-04-04 14:39:55.466967+00'),
	('81001656-731d-4551-bf5f-f4fa7e05b047', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-05', 'The customer''s eyes see what we''ve become blind to. Every day on the floor is a chance to see your store fresh and make it better.', 'Retail Wisdom', true, '2026-04-05 21:45:09.150306+00'),
	('3474951e-553f-4a1e-9cc7-999e387b2fed', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-06', 'Excellence is not a skill, it''s an attitude. When you choose to see every customer interaction, every display, every small task as an opportunity to get better, you transform ordinary work into extraordinary craft.', 'Original', true, '2026-04-06 05:00:04.06014+00'),
	('622b7b24-36ea-47cd-b5d1-8324dfa7406e', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-07', 'The only way to do great work is to love what you do.', 'Steve Jobs', false, '2026-04-07 14:04:48.244551+00'),
	('ec42d4fe-c007-44d1-8315-3836a8835cb0', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-08', 'Go see, ask why, show respect.', 'Fujio Cho', false, '2026-04-08 15:31:39.968813+00'),
	('7d4c9c6f-be54-4ccf-a017-172e69db833a', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-10', 'The floor is your laboratory. Every shift teaches you something new about how to serve customers better, move faster, and eliminate what doesn''t add value.', 'Original', true, '2026-04-10 20:55:52.936591+00'),
	('0eeb4b93-588a-4c6e-822e-c995eca67c6c', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-11', 'The customer''s experience is only as good as your last improvement. Every small enhancement you make today becomes tomorrow''s standard of excellence.', 'Original', true, '2026-04-11 17:42:06.504677+00'),
	('bbdfa75b-a03f-43d0-a13b-a8393cbd9a2c', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-12', 'The customer''s experience is only as strong as your weakest process. Every small improvement you make today creates a ripple of excellence that touches every person who walks through your doors.', 'Original', true, '2026-04-12 23:35:02.942826+00'),
	('f7d81fc6-9713-4cc5-98a9-110e010a9ff3', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-13', 'The gem cannot be polished without friction, nor man perfected without trials.', 'Chinese Proverb', true, '2026-04-13 12:11:30.593571+00'),
	('5cbd3b5b-e027-4c20-9487-7f9d5306c519', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-14', 'The secret to getting ahead is getting started. Every small improvement you make today becomes the foundation for tomorrow''s excellence.', 'Mark Twain (adapted)', true, '2026-04-14 13:36:55.271856+00'),
	('43c7233f-5df2-4668-837d-4f3037389b8f', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-15', 'The standard you walk past is the standard you accept. Every small improvement you make today becomes the foundation for tomorrow''s excellence.', 'David Hurley (adapted)', true, '2026-04-15 12:09:49.889012+00'),
	('80cb87d1-2fc4-4844-8ee9-6a4f7ab0ca2b', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-16', 'The customer sees the result of your work, but it''s your attention to the small details that creates the excellence they feel.', 'Original Wisdom', true, '2026-04-16 11:13:16.927728+00'),
	('cf8e14e9-e4be-4922-af51-455eab1677ff', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-17', 'Every small improvement you make today is a deposit in the bank of tomorrow''s excellence. The customer who walks into a better store, the teammate who benefits from your idea, the process you streamline – these are the compound returns on your daily efforts.', 'Original', true, '2026-04-17 10:50:50.554204+00');


