	('b5f714c0-1e36-417c-bbf1-6712f468a617', 'b0396051-34a1-475b-addc-771e580a5224', 'Shift Handoff Protocol', 'A structured handoff between shifts ensuring nothing falls through the cracks. Includes briefing, open issues review, and 3S.', 'shift_handoff', 15, NULL, true, 'A smooth handoff means nothing falls through the cracks. The outgoing team member shares what happened, what''s open, and what to watch for. The incoming team member asks questions and starts with 3S.', 1, NULL, 'system', '2026-02-24 23:04:11.237102+00', '2026-02-24 23:04:11.237102+00', NULL, false, NULL);


