	('b0ee10f6-799e-443d-92ed-259aaac9a482', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-25', '{"detail": "We''re showing $0 in sales today versus $2,334 last week, but this could be a system delay since we''re at day''s end. If sales are genuinely down, tomorrow''s a fresh opportunity to connect with customers.", "revenue": 0, "headline": "Zero showing but data delays happen - let''s verify!", "staleData": true, "suggestion": "Check with your POS system or manager to confirm if this is a data issue before day-end tasks", "generatedAt": "2026-02-25T12:03:20.460Z", "lastWeekRevenue": 2334.49, "transactionCount": 0, "averageOrderValue": 0}', '2026-02-25 12:03:20.460619+00'),
	('3068b46c-49b5-4304-8c3d-ff827656e239', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-26', '{"detail": "We''re showing $0 in sales today versus $2,334 last week, but this looks like a data sync problem rather than actual performance. The system note confirms sales data may be delayed, so don''t panic!", "revenue": 0, "headline": "Sales data showing zeros - likely a system delay issue", "staleData": true, "suggestion": "Check with your POS system or manager to confirm transactions are processing normally while we wait for the data to catch up.", "generatedAt": "2026-02-26T12:38:12.642Z", "lastWeekRevenue": 2334.49, "transactionCount": 0, "averageOrderValue": 0}', '2026-02-26 12:38:12.643622+00'),
	('4fe28db5-cefe-423e-b736-68b3a2b6b437', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-27', '{"detail": "We''re showing $0 today versus $8,440 same day last week, but since we''re seeing complete zeros across the board, this looks like a data delay rather than reality. Stay focused on great customer service while we wait for numbers to sync up.", "revenue": 0, "headline": "Zero showing but data might be catching up", "staleData": true, "suggestion": "Check with your POS system or manager about data connectivity - real sales rarely show perfect zeros", "generatedAt": "2026-02-27T12:02:05.653Z", "lastWeekRevenue": 8440.73, "transactionCount": 0, "averageOrderValue": 0}', '2026-02-27 12:02:05.654746+00'),
	('7986df38-ca42-4301-bae1-f2b1c53a1850', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-28', '{"detail": "We''re showing $0 in sales today versus $1,686 last week, but this looks like a system glitch since we''re 100% through the day. Sales data delays happen, and the real numbers are probably processing behind the scenes.", "revenue": 0, "headline": "Zero sales showing - likely a data delay situation", "staleData": true, "suggestion": "Check with your POS system or manager to confirm actual sales - this is almost certainly a technical issue, not reality!", "generatedAt": "2026-02-28T12:01:27.116Z", "lastWeekRevenue": 1686.1, "transactionCount": 0, "averageOrderValue": 0}', '2026-02-28 12:01:27.117054+00'),
