INSERT INTO public.morning_huddles (id, store_id, huddle_date, led_by, attendees, win_of_the_day, lean_principle, goals, heads_up, kudos_surfaced, ai_generated_content, status, started_at, completed_at, created_at) VALUES
	('a606cfd1-2359-488f-8ec5-b43caf91df5b', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-24', NULL, '[]', 'We''re starting fresh today with a clean slate and 91 tasks ready to tackle. Sometimes the best win is having a clear view of what needs our attention.', 'GO SEE — Don''t assume what''s happening on the floor or with inventory, go look at the actual situation. Walk the store, check the displays, see what customers are actually doing.', '["Get eyes on those 91 open tasks and prioritize the top 10 that will make the biggest customer impact", "Walk every section of the store to spot what really needs attention versus what we think needs attention", "Check in on any process that''s been running on autopilot — go see if it''s actually working", "Connect with at least 3 customers today to understand what they''re really looking for"]', '[]', '[]', '{"goals": ["Get eyes on those 91 open tasks and prioritize the top 10 that will make the biggest customer impact", "Walk every section of the store to spot what really needs attention versus what we think needs attention", "Check in on any process that''s been running on autopilot — go see if it''s actually working", "Connect with at least 3 customers today to understand what they''re really looking for"], "heads_up": [], "lean_principle": "GO SEE — Don''t assume what''s happening on the floor or with inventory, go look at the actual situation. Walk the store, check the displays, see what customers are actually doing.", "win_of_the_day": "We''re starting fresh today with a clean slate and 91 tasks ready to tackle. Sometimes the best win is having a clear view of what needs our attention."}', 'pending', NULL, NULL, '2026-02-24 20:36:14.66477+00'),
	('fabe8850-0a41-4fe1-9972-91b501ecd59a', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-25', NULL, '[]', 'Yesterday was a quiet day, but that means we get to start fresh today with full energy! Sometimes the best wins come from taking a breath and getting ready for what''s next.', 'RESPECT FOR PEOPLE — every person''s idea matters, every person''s time matters. Today, when someone shares an idea or asks for help, give them your full attention and show that their contribution counts.', '["Tackle those 91 open tasks with a team approach — let''s divide and conquer together", "Check in with each other regularly since we don''t have formal shifts scheduled today", "Use this flexible day to catch up on any training or SOPs we''ve been meaning to complete", "Create space for everyone to share ideas on how we can improve our processes"]', '[]', '[]', '{"goals": ["Tackle those 91 open tasks with a team approach — let''s divide and conquer together", "Check in with each other regularly since we don''t have formal shifts scheduled today", "Use this flexible day to catch up on any training or SOPs we''ve been meaning to complete", "Create space for everyone to share ideas on how we can improve our processes"], "heads_up": [], "lean_principle": "RESPECT FOR PEOPLE — every person''s idea matters, every person''s time matters. Today, when someone shares an idea or asks for help, give them your full attention and show that their contribution counts.", "win_of_the_day": "Yesterday was a quiet day, but that means we get to start fresh today with full energy! Sometimes the best wins come from taking a breath and getting ready for what''s next."}', 'pending', NULL, NULL, '2026-02-25 06:13:24.266523+00'),
	('a2c905cc-840e-4691-b47c-d91cabd6bb22', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-26', NULL, '[]', 'We''re starting fresh today with a clean slate and 91 opportunities to make an impact. Sometimes the biggest win is showing up ready to tackle what''s in front of us.', 'PDCA — Plan, Do, Check, Adjust. Try something small, see if it works, adjust. Pick one small process today and test a tiny improvement.', '["Knock out 15-20 tasks from our backlog to build momentum", "Identify which 5 tasks will have the biggest customer impact and prioritize those", "Try one small process improvement using PDCA and document what happens", "Set up tomorrow''s success by organizing remaining tasks into clear priorities"]', '[]', '[]', '{"goals": ["Knock out 15-20 tasks from our backlog to build momentum", "Identify which 5 tasks will have the biggest customer impact and prioritize those", "Try one small process improvement using PDCA and document what happens", "Set up tomorrow''s success by organizing remaining tasks into clear priorities"], "heads_up": [], "lean_principle": "PDCA — Plan, Do, Check, Adjust. Try something small, see if it works, adjust. Pick one small process today and test a tiny improvement.", "win_of_the_day": "We''re starting fresh today with a clean slate and 91 opportunities to make an impact. Sometimes the biggest win is showing up ready to tackle what''s in front of us."}', 'pending', NULL, NULL, '2026-02-26 12:38:08.518706+00'),
	('8a837cae-e1b3-4c64-b36e-c4f07bb52511', 'b0396051-34a1-475b-addc-771e580a5224', '2026-02-27', NULL, '[]', 'Our team tackled another day with determination, keeping our doors open and ready for customers. That consistent commitment is what builds trust with our community.', 'WASTE WALK — walk the store looking for the 8 wastes: defects, overproduction, waiting, unused talent, transportation, inventory, motion, extra processing. Spend 10 minutes today spotting what slows us down.', '["Chip away at those 91 open tasks — let''s knock out 15 today.", "Do a thorough waste walk and identify 3 specific improvements we can make.", "Focus on customer experience since it''s Friday — make every interaction count.", "Set up systems now so Monday starts smooth.", "Take care of any maintenance or organization that''ll help next week."]', '[]', '[]', '{"goals": ["Chip away at those 91 open tasks — let''s knock out 15 today.", "Do a thorough waste walk and identify 3 specific improvements we can make.", "Focus on customer experience since it''s Friday — make every interaction count.", "Set up systems now so Monday starts smooth.", "Take care of any maintenance or organization that''ll help next week."], "heads_up": [], "lean_principle": "WASTE WALK — walk the store looking for the 8 wastes: defects, overproduction, waiting, unused talent, transportation, inventory, motion, extra processing. Spend 10 minutes today spotting what slows us down.", "win_of_the_day": "Our team tackled another day with determination, keeping our doors open and ready for customers. That consistent commitment is what builds trust with our community."}', 'pending', NULL, NULL, '2026-02-27 06:15:08.982258+00'),
