	('4de1db4f-ee0b-4cc2-b103-23f5833fbe1b', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-02', NULL, '[]', 'We''re starting fresh this Monday with a clean slate and 91 tasks ready to tackle. That''s 91 opportunities to make our store better today.', 'KAIZEN — change for the better. Every single day. Pick one small thing that bugs you about our process and fix it today.', '["Knock out at least 20 of those 91 open tasks before noon.", "Each person identifies one tiny improvement they can make to their routine today.", "Set up a simple system to track our daily wins moving forward.", "Focus on completing tasks fully rather than starting new ones."]', '["No scheduled shifts showing up in the system — double check your schedules and confirm coverage."]', '[]', '{"goals": ["Knock out at least 20 of those 91 open tasks before noon.", "Each person identifies one tiny improvement they can make to their routine today.", "Set up a simple system to track our daily wins moving forward.", "Focus on completing tasks fully rather than starting new ones."], "heads_up": ["No scheduled shifts showing up in the system — double check your schedules and confirm coverage."], "lean_principle": "KAIZEN — change for the better. Every single day. Pick one small thing that bugs you about our process and fix it today.", "win_of_the_day": "We''re starting fresh this Monday with a clean slate and 91 tasks ready to tackle. That''s 91 opportunities to make our store better today."}', 'pending', NULL, NULL, '2026-03-02 15:31:09.716181+00'),
