	('70f88dc6-54c6-4209-ad7d-acf79d3e0010', 'b0396051-34a1-475b-addc-771e580a5224', '2026-03-04', NULL, '[]', 'Taylor Holman earned kudos from Libby Story for great teamwork yesterday! That''s the collaborative spirit that makes our boutique special.', 'PULL DON''T PUSH — Instead of guessing what needs to be done, respond to what customers and the business actually need right now. Look at real demand before diving into tasks.', '["Tackle the 91 open tasks by prioritizing what customers need most urgently first.", "Check in with teammates to see where collaboration can help move things forward faster.", "Apply Pull Don''t Push by asking ''What''s actually needed right now?'' before starting each task.", "Create momentum by completing at least 5 tasks that directly impact customer experience."]', '[]', '[]', '{"goals": ["Tackle the 91 open tasks by prioritizing what customers need most urgently first.", "Check in with teammates to see where collaboration can help move things forward faster.", "Apply Pull Don''t Push by asking ''What''s actually needed right now?'' before starting each task.", "Create momentum by completing at least 5 tasks that directly impact customer experience."], "heads_up": [], "kudos_summary": "Taylor Holman got recognized by Libby Story for great teamwork — love seeing our team support each other!", "lean_principle": "PULL DON''T PUSH — Instead of guessing what needs to be done, respond to what customers and the business actually need right now. Look at real demand before diving into tasks.", "win_of_the_day": "Taylor Holman earned kudos from Libby Story for great teamwork yesterday! That''s the collaborative spirit that makes our boutique special."}', 'pending', NULL, NULL, '2026-03-04 15:37:37.611515+00'),
