	('3efa91b3-341a-4d0e-a1c2-fb50e6d972cb', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-02', NULL, '[]', 'Team, we''re starting fresh today with a clean slate and 91 opportunities to make real progress. Sometimes the best wins come from organized action!', 'ONE PIECE FLOW — finish one task completely before starting the next. Pick your first task, crush it, then move to the next one.', '["Tackle 15-20 of those 91 open tasks using one piece flow method.", "Get at least 3 SOPs completed and documented properly.", "Set up tomorrow''s schedule so we have clear coverage planned.", "Create a simple priority system for the remaining open tasks."]', '[]', '[]', '{"goals": ["Tackle 15-20 of those 91 open tasks using one piece flow method.", "Get at least 3 SOPs completed and documented properly.", "Set up tomorrow''s schedule so we have clear coverage planned.", "Create a simple priority system for the remaining open tasks."], "heads_up": [], "lean_principle": "ONE PIECE FLOW — finish one task completely before starting the next. Pick your first task, crush it, then move to the next one.", "win_of_the_day": "Team, we''re starting fresh today with a clean slate and 91 opportunities to make real progress. Sometimes the best wins come from organized action!"}', 'pending', NULL, NULL, '2026-04-02 14:03:49.28018+00'),
	('0d726329-08d2-4577-a9a3-af2d60bf356c', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-03', NULL, '[]', 'We''re starting fresh today with a clean slate! Sometimes the best wins come from new beginnings and focused energy.', 'STANDARD WORK — the best known way to do something, until someone finds a better way. Today, let''s tackle those 91 open tasks by following our proven processes first, then improving them as we go.', '["Cut through at least 20 of those 91 open tasks by focusing on quick wins first.", "Document one process improvement while working through tasks today.", "Set up clear priorities for the weekend and next week''s success.", "Create momentum by completing the easiest tasks first, then building up to bigger ones."]', '[]', '[]', '{"goals": ["Cut through at least 20 of those 91 open tasks by focusing on quick wins first.", "Document one process improvement while working through tasks today.", "Set up clear priorities for the weekend and next week''s success.", "Create momentum by completing the easiest tasks first, then building up to bigger ones."], "heads_up": [], "lean_principle": "STANDARD WORK — the best known way to do something, until someone finds a better way. Today, let''s tackle those 91 open tasks by following our proven processes first, then improving them as we go.", "win_of_the_day": "We''re starting fresh today with a clean slate! Sometimes the best wins come from new beginnings and focused energy."}', 'pending', NULL, NULL, '2026-04-03 14:21:45.581124+00'),
	('eaf21a54-e907-4e4e-8380-56cea155eed2', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-04', NULL, '[]', 'We''re starting fresh today with a clean slate and 91 opportunities to make improvements. Sometimes the biggest win is having the chance to build momentum from the ground up.', 'GROW PEOPLE FIRST — lean is always spelled P-E-O-P-L-E. Today, focus on developing each other through those 91 open tasks — teach someone something new, ask for help when you need it, and celebrate small wins together.', '["Tackle the task backlog strategically — pick 5 high-impact items to complete as a team.", "Use today to cross-train on different areas since we have flexibility in our schedule.", "Document any processes as you work through tasks to make future work smoother.", "Set up systems to better track our daily wins and progress going forward."]', '[]', '[]', '{"goals": ["Tackle the task backlog strategically — pick 5 high-impact items to complete as a team.", "Use today to cross-train on different areas since we have flexibility in our schedule.", "Document any processes as you work through tasks to make future work smoother.", "Set up systems to better track our daily wins and progress going forward."], "heads_up": [], "lean_principle": "GROW PEOPLE FIRST — lean is always spelled P-E-O-P-L-E. Today, focus on developing each other through those 91 open tasks — teach someone something new, ask for help when you need it, and celebrate small wins together.", "win_of_the_day": "We''re starting fresh today with a clean slate and 91 opportunities to make improvements. Sometimes the biggest win is having the chance to build momentum from the ground up."}', 'pending', NULL, NULL, '2026-04-04 14:40:02.855625+00'),
	('8689c8b8-aebd-4d8a-83e7-047d0a274987', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-05', NULL, '[]', 'We''ve got a fresh Sunday ahead with a clean slate! Sometimes the best wins come from having space to tackle what really matters.', 'GO SEE — don''t assume, go look at the actual situation. Today''s perfect for walking the floor, checking displays, and seeing what customers actually experience firsthand.', '["Tackle those 91 open tasks — let''s knock out at least 20 high-impact ones today", "Do a full store walk-through and document what really needs attention", "Prep the team schedule and priorities for the busy week ahead", "Check inventory levels and merchandising — Sunday''s great for this deep dive"]', '[]', '[]', '{"goals": ["Tackle those 91 open tasks — let''s knock out at least 20 high-impact ones today", "Do a full store walk-through and document what really needs attention", "Prep the team schedule and priorities for the busy week ahead", "Check inventory levels and merchandising — Sunday''s great for this deep dive"], "heads_up": [], "lean_principle": "GO SEE — don''t assume, go look at the actual situation. Today''s perfect for walking the floor, checking displays, and seeing what customers actually experience firsthand.", "win_of_the_day": "We''ve got a fresh Sunday ahead with a clean slate! Sometimes the best wins come from having space to tackle what really matters."}', 'pending', NULL, NULL, '2026-04-05 21:45:14.356217+00'),
	('c0c51e74-5218-4d87-a2a0-ede6c2a28b48', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-06', NULL, '[]', 'We''re starting fresh today with a clean slate! Sometimes the best wins come from having space to build something amazing.', 'RESPECT FOR PEOPLE — every person''s idea matters, every person''s time matters. Today, let''s make sure everyone''s voice is heard when tackling our task list.', '["Tackle those 91 open tasks as a team — let''s break them into bite-sized wins.", "Get clear on who''s working today and create a game plan that works for everyone.", "Set up a simple system to track our progress throughout the day.", "Make time for quick check-ins so nobody feels stuck or overwhelmed."]', '["We have 91 tasks waiting for us — sounds like a lot, but we''ve got this if we work smart together."]', '[]', '{"goals": ["Tackle those 91 open tasks as a team — let''s break them into bite-sized wins.", "Get clear on who''s working today and create a game plan that works for everyone.", "Set up a simple system to track our progress throughout the day.", "Make time for quick check-ins so nobody feels stuck or overwhelmed."], "heads_up": ["We have 91 tasks waiting for us — sounds like a lot, but we''ve got this if we work smart together."], "lean_principle": "RESPECT FOR PEOPLE — every person''s idea matters, every person''s time matters. Today, let''s make sure everyone''s voice is heard when tackling our task list.", "win_of_the_day": "We''re starting fresh today with a clean slate! Sometimes the best wins come from having space to build something amazing."}', 'in_progress', '2026-04-06 19:10:19.559+00', NULL, '2026-04-06 06:00:08.357945+00'),
	('ee08ccdf-859b-4102-b659-ae5f8a295caf', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-07', NULL, '[]', 'We''re starting fresh today with a clean slate and 91 opportunities to make an impact. That''s not a burden — that''s potential energy waiting to be unleashed!', 'PDCA — Plan, Do, Check, Adjust. Try something small, see if it works, adjust. Pick one task today, test a new approach, and see what happens.', '["Tackle 15 of those 91 open tasks — small wins build momentum.", "Complete at least 2 SOPs to get our processes flowing again.", "Test one new approach to task management using PDCA.", "Set up tomorrow''s schedule so we''re not flying blind."]', '[]', '[]', '{"goals": ["Tackle 15 of those 91 open tasks — small wins build momentum.", "Complete at least 2 SOPs to get our processes flowing again.", "Test one new approach to task management using PDCA.", "Set up tomorrow''s schedule so we''re not flying blind."], "heads_up": [], "lean_principle": "PDCA — Plan, Do, Check, Adjust. Try something small, see if it works, adjust. Pick one task today, test a new approach, and see what happens.", "win_of_the_day": "We''re starting fresh today with a clean slate and 91 opportunities to make an impact. That''s not a burden — that''s potential energy waiting to be unleashed!"}', 'pending', NULL, NULL, '2026-04-07 14:04:52.967992+00'),
	('d7dfb896-9d95-448c-be7c-ea1aa5d7ec68', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-08', NULL, '[]', 'We''re starting fresh today with a clean slate and 91 open tasks that give us clear direction on where to make impact. Sometimes the biggest win is having clarity on what needs our attention.', 'WASTE WALK — walk the store looking for the 8 wastes: defects, overproduction, waiting, unused talent, transportation, inventory, motion, extra processing. Spend 10 minutes this morning identifying one small improvement we can make today.', '["Tackle our open task list strategically — pick 5 high-impact items to complete first.", "Do a thorough waste walk and document 3 specific improvements we can implement.", "Set up systems to track our daily wins moving forward.", "Check in with each other throughout the day since schedules are flexible today."]', '[]', '[]', '{"goals": ["Tackle our open task list strategically — pick 5 high-impact items to complete first.", "Do a thorough waste walk and document 3 specific improvements we can implement.", "Set up systems to track our daily wins moving forward.", "Check in with each other throughout the day since schedules are flexible today."], "heads_up": [], "lean_principle": "WASTE WALK — walk the store looking for the 8 wastes: defects, overproduction, waiting, unused talent, transportation, inventory, motion, extra processing. Spend 10 minutes this morning identifying one small improvement we can make today.", "win_of_the_day": "We''re starting fresh today with a clean slate and 91 open tasks that give us clear direction on where to make impact. Sometimes the biggest win is having clarity on what needs our attention."}', 'pending', NULL, NULL, '2026-04-08 15:31:47.101411+00'),
	('074045cf-72aa-4928-9bb4-4c5a35291d47', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-10', NULL, '[]', 'We''re here and ready to tackle Friday! Sometimes the biggest win is showing up with energy when the data doesn''t tell the whole story.', 'GEMBA — the real answers are where the work happens, not in a spreadsheet. Get on the floor, talk to customers, see what''s actually happening in our space today.', '["Knock out at least 15 of those 91 open tasks before lunch", "Walk the floor every hour to spot what needs fixing that no system tracks", "Connect with every customer who walks in — their reactions tell us more than any report", "End Friday stronger than we started, even without perfect data"]', '[]', '[]', '{"goals": ["Knock out at least 15 of those 91 open tasks before lunch", "Walk the floor every hour to spot what needs fixing that no system tracks", "Connect with every customer who walks in — their reactions tell us more than any report", "End Friday stronger than we started, even without perfect data"], "heads_up": [], "lean_principle": "GEMBA — the real answers are where the work happens, not in a spreadsheet. Get on the floor, talk to customers, see what''s actually happening in our space today.", "win_of_the_day": "We''re here and ready to tackle Friday! Sometimes the biggest win is showing up with energy when the data doesn''t tell the whole story."}', 'pending', NULL, NULL, '2026-04-10 20:55:58.092796+00'),
	('5aa8950d-756c-4b1f-aeb5-9fde32761d77', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-11', NULL, '[]', 'The team cleared the deck yesterday and now we have a clean slate to tackle today! Sometimes the best win is having space to make real progress.', 'KAIZEN — change for the better. Every single day. Today we''ll pick one small thing from our 91 open tasks and make it better than it was yesterday.', '["Knock out 10 quick wins from our task list to build momentum", "Identify the 3 most important tasks that will move the needle this week", "Spend 15 minutes organizing the remaining tasks by priority", "Find one process we can improve while working through today''s tasks"]', '[]', '[]', '{"goals": ["Knock out 10 quick wins from our task list to build momentum", "Identify the 3 most important tasks that will move the needle this week", "Spend 15 minutes organizing the remaining tasks by priority", "Find one process we can improve while working through today''s tasks"], "heads_up": [], "lean_principle": "KAIZEN — change for the better. Every single day. Today we''ll pick one small thing from our 91 open tasks and make it better than it was yesterday.", "win_of_the_day": "The team cleared the deck yesterday and now we have a clean slate to tackle today! Sometimes the best win is having space to make real progress."}', 'pending', NULL, NULL, '2026-04-11 17:42:10.78891+00'),
	('c648e6dd-3d56-4371-8ed5-6f059e4477a7', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-12', NULL, '[]', 'We''re starting fresh today with a clean slate! Perfect opportunity to tackle those 91 open tasks and set ourselves up for an amazing week ahead.', 'VISUAL MANAGEMENT — organize so anyone can see what''s normal and what''s not in 5 seconds. Today, let''s create clear visual systems for our task board so everyone can instantly spot what needs attention.', '["Organize those 91 open tasks into clear priority categories using visual labels or zones", "Complete at least 15 high-impact tasks to build momentum for the week", "Set up visual management systems for common work areas so problems jump out immediately", "Prepare the store layout and displays for Monday''s fresh start", "Use today''s quieter pace to cross-train on any SOPs we''ve been meaning to tackle"]', '[]', '[]', '{"goals": ["Organize those 91 open tasks into clear priority categories using visual labels or zones", "Complete at least 15 high-impact tasks to build momentum for the week", "Set up visual management systems for common work areas so problems jump out immediately", "Prepare the store layout and displays for Monday''s fresh start", "Use today''s quieter pace to cross-train on any SOPs we''ve been meaning to tackle"], "heads_up": [], "lean_principle": "VISUAL MANAGEMENT — organize so anyone can see what''s normal and what''s not in 5 seconds. Today, let''s create clear visual systems for our task board so everyone can instantly spot what needs attention.", "win_of_the_day": "We''re starting fresh today with a clean slate! Perfect opportunity to tackle those 91 open tasks and set ourselves up for an amazing week ahead."}', 'pending', NULL, NULL, '2026-04-12 23:35:08.937054+00'),
	('cd38f93b-9fff-43d5-8b4b-f00e0796687d', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-13', NULL, '[]', 'Fresh week, fresh energy! We''re starting Monday with a clean slate and 91 opportunities waiting for us to tackle.', 'PULL DON''T PUSH — Instead of guessing what needs doing first, let customer needs and urgent deadlines pull your attention to the right tasks today.', '["Knock out at least 15 of those 91 open tasks by focusing on customer-facing priorities first.", "Get one SOP completed today to build momentum for the week.", "Check in with each team member to see what support they need most.", "Identify which of those open tasks can be quick wins vs. deeper projects.", "End the day with a clear plan for Tuesday''s priorities."]', '[]', '[]', '{"goals": ["Knock out at least 15 of those 91 open tasks by focusing on customer-facing priorities first.", "Get one SOP completed today to build momentum for the week.", "Check in with each team member to see what support they need most.", "Identify which of those open tasks can be quick wins vs. deeper projects.", "End the day with a clear plan for Tuesday''s priorities."], "heads_up": [], "lean_principle": "PULL DON''T PUSH — Instead of guessing what needs doing first, let customer needs and urgent deadlines pull your attention to the right tasks today.", "win_of_the_day": "Fresh week, fresh energy! We''re starting Monday with a clean slate and 91 opportunities waiting for us to tackle."}', 'pending', NULL, NULL, '2026-04-13 12:11:36.047188+00'),
	('5bca0526-9e98-49fb-9d1b-27aa986b2b32', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-14', NULL, '[]', 'We''ve got a fresh start today with a clean slate to tackle our 91 open tasks. Sometimes the biggest win is having clarity on what needs to get done.', 'FLOW — remove the blockers that make work stop and start. Today, identify one thing that constantly interrupts your workflow and eliminate it.', '["Prioritize the top 10 most critical tasks from our 91 open items and knock them out first", "Create a simple system to categorize remaining tasks by urgency and impact", "Identify what''s been blocking progress on these tasks and remove at least 3 barriers", "Set up proper scheduling so we''re not flying blind tomorrow", "Document one process that keeps getting repeated so we can streamline it"]', '["We need to get our scheduling system back on track — let''s make that a priority today"]', '[]', '{"goals": ["Prioritize the top 10 most critical tasks from our 91 open items and knock them out first", "Create a simple system to categorize remaining tasks by urgency and impact", "Identify what''s been blocking progress on these tasks and remove at least 3 barriers", "Set up proper scheduling so we''re not flying blind tomorrow", "Document one process that keeps getting repeated so we can streamline it"], "heads_up": ["We need to get our scheduling system back on track — let''s make that a priority today"], "lean_principle": "FLOW — remove the blockers that make work stop and start. Today, identify one thing that constantly interrupts your workflow and eliminate it.", "win_of_the_day": "We''ve got a fresh start today with a clean slate to tackle our 91 open tasks. Sometimes the biggest win is having clarity on what needs to get done."}', 'pending', NULL, NULL, '2026-04-14 13:37:01.311856+00'),
	('963f6368-24e7-4307-960d-c02e05c1792e', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-15', NULL, '["9857c7bc-3ef4-43c0-a855-91697a37c6cf", "041919c0-9407-4a85-b529-b2643cdbba84", "ee885887-a827-4383-b91f-cb6a7b9bde8e"]', 'Taylor earned a customer service shoutout from Jh Mac yesterday — ''Amazing customer service!'' Those are the moments that build our reputation one interaction at a time.', 'JIDOKA — if something is wrong, stop and fix it now, not later. When you spot an issue today, pause and address it immediately rather than letting it snowball.', '["Tackle those 91 open tasks — let''s chip away at that mountain and make real progress", "Keep that customer service magic flowing that earned Taylor yesterday''s kudos", "Use the single-person shift as focused time to deep-dive on priority items without distractions", "Document any processes or fixes you make so the next person can build on your work"]', '["Flying solo today with just Taylor on shift — perfect opportunity for concentrated work on those open tasks"]', '[]', '{"goals": ["Tackle those 91 open tasks — let''s chip away at that mountain and make real progress", "Keep that customer service magic flowing that earned Taylor yesterday''s kudos", "Use the single-person shift as focused time to deep-dive on priority items without distractions", "Document any processes or fixes you make so the next person can build on your work"], "heads_up": ["Flying solo today with just Taylor on shift — perfect opportunity for concentrated work on those open tasks"], "kudos_summary": "Shoutout to Taylor for the amazing customer service that caught Jh Mac''s attention yesterday — keep that energy going!", "lean_principle": "JIDOKA — if something is wrong, stop and fix it now, not later. When you spot an issue today, pause and address it immediately rather than letting it snowball.", "win_of_the_day": "Taylor earned a customer service shoutout from Jh Mac yesterday — ''Amazing customer service!'' Those are the moments that build our reputation one interaction at a time."}', 'completed', '2026-04-15 17:37:03.163+00', '2026-04-15 17:38:49.911+00', '2026-04-15 12:09:56.949447+00'),
	('d3e59246-8abc-477d-8542-b8f6cb983aae', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-16', NULL, '[]', 'Yesterday we hit $1147 in sales with just 8 orders — that''s a solid $143 average order value! Our customers are really investing in quality pieces.', 'HANSEI — honest self-reflection. What can I personally do better tomorrow? Take 2 minutes at day''s end to write down one thing you''ll improve.', '["Tackle at least 15 of those 91 open tasks before Taylor arrives at 2 PM", "Focus on upselling and cross-selling to keep that high AOV momentum going", "Complete at least 2 overdue SOPs during the morning shift", "Set Taylor up for success with a clean handoff at 2 PM"]', '[]', '[]', '{"goals": ["Tackle at least 15 of those 91 open tasks before Taylor arrives at 2 PM", "Focus on upselling and cross-selling to keep that high AOV momentum going", "Complete at least 2 overdue SOPs during the morning shift", "Set Taylor up for success with a clean handoff at 2 PM"], "heads_up": [], "lean_principle": "HANSEI — honest self-reflection. What can I personally do better tomorrow? Take 2 minutes at day''s end to write down one thing you''ll improve.", "win_of_the_day": "Yesterday we hit $1147 in sales with just 8 orders — that''s a solid $143 average order value! Our customers are really investing in quality pieces."}', 'pending', NULL, NULL, '2026-04-16 11:13:21.944142+00'),
	('c9675ffc-2091-4c60-acdd-80289623a36e', 'b0396051-34a1-475b-addc-771e580a5224', '2026-04-17', NULL, '[]', 'We crushed yesterday''s sales with $4,110.85 from 31 orders! That''s over $130 average per transaction — our customers are really connecting with our products.', 'ACTION THIS DAY — if you see something that needs fixing, fix it NOW. Don''t wait for Monday, don''t put it on a list. See a display that''s messy? Fix it. Notice inventory running low? Order it. Take action today.', '["Tackle those 91 open tasks — let''s knock out at least 15 today", "Complete 2 SOPs that we''ve been putting off", "Keep that sales momentum going with strong Friday energy", "Walk the floor every hour and fix anything that catches your eye immediately"]', '[]', '[]', '{"goals": ["Tackle those 91 open tasks — let''s knock out at least 15 today", "Complete 2 SOPs that we''ve been putting off", "Keep that sales momentum going with strong Friday energy", "Walk the floor every hour and fix anything that catches your eye immediately"], "heads_up": [], "lean_principle": "ACTION THIS DAY — if you see something that needs fixing, fix it NOW. Don''t wait for Monday, don''t put it on a list. See a display that''s messy? Fix it. Notice inventory running low? Order it. Take action today.", "win_of_the_day": "We crushed yesterday''s sales with $4,110.85 from 31 orders! That''s over $130 average per transaction — our customers are really connecting with our products."}', 'pending', NULL, NULL, '2026-04-17 10:50:56.904007+00');


