INSERT INTO public.weekly_reviews (id, store_id, user_id, review_week_start, ai_content, status, started_at, completed_at, notes, created_at) VALUES
	('e12451e4-16a5-4aa5-818b-ab509a995c94', 'b0396051-34a1-475b-addc-771e580a5224', 'c49ed603-fe4d-4dd8-aaee-97ddf58716e6', '2026-02-23', '{"greeting": "Happy Friday! Time for your weekly check-in — let''s see how this week shaped up.", "sop_stats": {"total": 0, "completed": 0}, "inbox_status": {"message": "Your inbox is beautifully clear — staying at zero is an art form! 🎯", "unprocessed_count": 0, "processed_this_week": 0}, "week_summary": "This week was remarkably quiet on the operational front. While a clean slate can feel peaceful, it might also signal that your system needs some fresh energy and engagement.", "someday_items": [], "sales_snapshot": "Sales data not available this week", "closing_thought": "Sometimes a quiet week is exactly what we need to reset and refocus. Use this clean slate as an opportunity to plant some new seeds for growth. What one meaningful project could you start next week?", "overdue_actions": {"count": 0, "items": [], "message": "No overdue items cluttering your mental space — you''re starting fresh for next week."}, "projects_review": [], "waiting_for_check": {"items": [], "message": "Nothing hanging in limbo right now — all clear on the follow-up front.", "overdue_count": 0}, "improvement_insights": "No improvement activities captured this week. Consider whether your team knows how to submit ''What Bugged You'' items, or if there are small friction points going unnoticed that could become learning opportunities.", "someday_maybe_prompt": "With no items in your someday/maybe list, this might be the perfect time to brainstorm: What dreams or ideas have been floating in the back of your mind? What would you tackle if you had unlimited time and resources?"}', 'pending', NULL, NULL, NULL, '2026-02-27 14:47:10.617289+00'),
	('108e4a4c-3b75-49d5-beb0-66189adb5d3b', 'b0396051-34a1-475b-addc-771e580a5224', '8adcca37-29a7-4dc6-99b6-342b7f20e061', '2026-02-23', '{"greeting": "Happy Friday! Hope you''re ready for a nice quiet weekend after a peaceful week.", "sop_stats": {"total": 0, "completed": 0}, "inbox_status": {"message": "Perfect! Your inbox stayed at zero all week. That''s the sweet spot where you can focus on what matters most.", "unprocessed_count": 0, "processed_this_week": 0}, "week_summary": "This was quite the zen week — everything stayed beautifully organized with zero inbox buildup and no fires to put out. Sometimes the best weeks are the ones where the systems just hum along quietly in the background.", "someday_items": [], "sales_snapshot": "Sales data not available this week", "closing_thought": "Sometimes the most productive weeks are the quiet ones where everything just flows. You''ve created systems that work even when you''re not constantly managing them. That''s the sign of great leadership. Enjoy your weekend!", "overdue_actions": {"count": 0, "items": [], "message": "Clean slate here too — nothing overdue means you''re staying on top of commitments."}, "projects_review": [], "waiting_for_check": {"items": [], "message": "No pending follow-ups this week. Everyone''s staying responsive, or maybe it''s just been that kind of smooth week.", "overdue_count": 0}, "improvement_insights": "No bugs reported this week and no new training videos — either the team is hitting their stride, or maybe it''s time to proactively ask what small improvements they''d love to see.", "someday_maybe_prompt": "With everything so calm, this might be the perfect time to dream a little. What''s one small project or improvement that''s been quietly brewing in the back of your mind?"}', 'pending', NULL, NULL, NULL, '2026-02-27 14:47:20.734883+00'),
	('9c801c92-ad14-451f-89bc-34d04d861c49', 'b0396051-34a1-475b-addc-771e580a5224', '5015ab95-a466-4d26-9bf2-eaadc73a9cb4', '2026-02-23', '{"greeting": "Happy Friday! Time for your weekly check-in — looks like you''re starting with a completely clean slate.", "sop_stats": {"total": 0, "completed": 0}, "inbox_status": {"message": "Inbox zero achieved! Now''s the perfect time to capture anything floating around in your head or on sticky notes.", "unprocessed_count": 0, "processed_this_week": 0}, "week_summary": "This week appears to have been either incredibly efficient or perhaps you''re just getting started with the system. Either way, having zero items across all categories gives us a perfect foundation to build from.", "someday_items": [], "sales_snapshot": "Sales data not available this week", "closing_thought": "A blank canvas can be intimidating or exciting — choose exciting! You have a clean system ready to capture all the great ideas and projects that will move your boutique forward. Here''s to a productive week ahead!", "overdue_actions": {"count": 0, "items": [], "message": "No overdue items to worry about — you''re starting fresh!"}, "projects_review": [], "waiting_for_check": {"items": [], "message": "No pending follow-ups right now, but keep an eye out for things you delegate or request next week.", "overdue_count": 0}, "improvement_insights": "No ''What Bugged You'' submissions or improvement videos this week — consider encouraging your team to start capturing those small frustrations that could become big wins when solved.", "someday_maybe_prompt": "Since your someday/maybe list is empty, this is a great time to brainstorm: What''s one thing you''ve been thinking about doing for the boutique but haven''t captured yet? A new display idea? A partnership? A process improvement?"}', 'pending', NULL, NULL, NULL, '2026-02-27 14:47:30.657822+00'),
